package com.pessoal.agenda.infra;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.*;

/**
 * Infraestrutura de banco de dados SQLite.
 * Responsavel por fornecer conexoes e executar a migracao de schema.
 * Todos os repositorios dependem desta classe.
 */
public class Database {

    private final String jdbcUrl;

    public Database() {
        this.jdbcUrl = resolveJdbcUrl();
    }

    private String resolveJdbcUrl() {
        Path appDir = Path.of(System.getProperty("user.home"), ".agenda-pessoal");
        try {
            Files.createDirectories(appDir);
        } catch (IOException e) {
            throw new RuntimeException("Nao foi possivel criar diretorio de dados", e);
        }
        return "jdbc:sqlite:" + appDir.resolve("agenda.db");
    }

    /** Abre uma nova conexao JDBC. O chamador e responsavel por fechar. */
    public Connection connect() throws SQLException {
        return DriverManager.getConnection(jdbcUrl);
    }

    // ── Helpers compartilhados por repositorios ────────────────────────────

    /** Executa um UPDATE/INSERT/DELETE com parametros posicionais. */
    public void execute(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            ps.executeUpdate();
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao executar SQL: " + sql, e);
        }
    }

    /** Executa um SELECT e retorna o primeiro inteiro da primeira linha. */
    public int queryInt(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next() ? rs.getInt(1) : 0;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao consultar (int): " + sql, e);
        }
    }

    /** Executa um SELECT e retorna o primeiro double da primeira linha. */
    public double queryDouble(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next() ? rs.getDouble(1) : 0.0;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao consultar (double): " + sql, e);
        }
    }

    private void bindParams(PreparedStatement ps, Object[] params) throws SQLException {
        for (int i = 0; i < params.length; i++) ps.setObject(i + 1, params[i]);
    }

    // ── Migracao de schema ─────────────────────────────────────────────────

    /** Cria tabelas e aplica migrações incrementais. Idempotente. */
    public void runMigrations() {
        try (Connection conn = connect(); Statement stmt = conn.createStatement()) {
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS tasks (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    notes TEXT,
                    due_date TEXT NOT NULL,
                    done INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    protocol_name TEXT NOT NULL,
                    item_text TEXT NOT NULL,
                    done INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS finance_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    entry_type TEXT NOT NULL,
                    description TEXT NOT NULL,
                    amount REAL NOT NULL,
                    due_date TEXT,
                    paid INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS sales_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    product_name TEXT NOT NULL,
                    quantity INTEGER NOT NULL,
                    unit_price REAL NOT NULL,
                    sale_date TEXT NOT NULL,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS inventory_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    product_name TEXT NOT NULL,
                    quantity INTEGER NOT NULL,
                    minimum_quantity INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_sessions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    subject TEXT NOT NULL,
                    session_date TEXT NOT NULL,
                    duration_minutes INTEGER NOT NULL,
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS project_ideas (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    description TEXT,
                    status TEXT NOT NULL,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // Tabela de categorias personalizadas por dominio
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS categories (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    domain TEXT NOT NULL,
                    color TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    UNIQUE(name, domain)
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_plans (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    study_type TEXT NOT NULL DEFAULT 'GERAL',
                    category TEXT NOT NULL DEFAULT 'Geral',
                    description TEXT,
                    start_date TEXT,
                    target_date TEXT,
                    status TEXT NOT NULL DEFAULT 'PLANEJADO',
                    total_pages INTEGER NOT NULL DEFAULT 0,
                    current_page INTEGER NOT NULL DEFAULT 0,
                    progress_percent REAL NOT NULL DEFAULT 0.0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_id INTEGER NOT NULL,
                    entry_title TEXT,
                    entry_date TEXT NOT NULL,
                    content TEXT,
                    duration_minutes INTEGER NOT NULL DEFAULT 0,
                    page_start INTEGER NOT NULL DEFAULT 0,
                    page_end INTEGER NOT NULL DEFAULT 0,
                    entry_order INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // ── Protocolos Operacionais ────────────────────────────────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocols (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    execution_type TEXT NOT NULL DEFAULT 'RECORRENTE',
                    category TEXT NOT NULL DEFAULT 'Geral',
                    description TEXT,
                    linked_task_id INTEGER,
                    validity_days INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_steps (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    template_id INTEGER NOT NULL,
                    step_order INTEGER NOT NULL DEFAULT 0,
                    step_text TEXT NOT NULL,
                    notes TEXT,
                    critical INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_executions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    template_id INTEGER NOT NULL,
                    iteration_number INTEGER NOT NULL DEFAULT 1,
                    started_at TEXT NOT NULL,
                    completed_at TEXT,
                    status TEXT NOT NULL DEFAULT 'ATIVA',
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_execution_steps (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    execution_id INTEGER NOT NULL,
                    step_id INTEGER NOT NULL,
                    step_text TEXT NOT NULL,
                    step_notes TEXT,
                    critical INTEGER NOT NULL DEFAULT 0,
                    step_order INTEGER NOT NULL DEFAULT 0,
                    checked INTEGER NOT NULL DEFAULT 0,
                    checked_at TEXT,
                    observation_notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // Protocolos: validade em dias (coluna pode já existir)
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_schedules (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_plan_id INTEGER NOT NULL,
                    day_of_week INTEGER NOT NULL,
                    min_minutes INTEGER NOT NULL DEFAULT 30,
                    UNIQUE(study_plan_id, day_of_week)
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_compensations (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_plan_id INTEGER NOT NULL,
                    missed_date TEXT NOT NULL,
                    compensation_date TEXT,
                    compensation_minutes INTEGER NOT NULL DEFAULT 0,
                    status TEXT NOT NULL DEFAULT 'PENDENTE',
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
                )""");

            // ── Checklist de Próximas Ações (Ideias / Projetos) ───────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS idea_checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    idea_id INTEGER NOT NULL,
                    text TEXT NOT NULL DEFAULT '',
                    done INTEGER NOT NULL DEFAULT 0,
                    position INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // ── Checklist de Tarefas da Agenda ─────────────────────────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS task_checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    task_id INTEGER NOT NULL,
                    text TEXT NOT NULL DEFAULT '',
                    done INTEGER NOT NULL DEFAULT 0,
                    position INTEGER NOT NULL DEFAULT 0,
                    kanban_column TEXT NOT NULL DEFAULT 'backlog',
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

        } catch (SQLException e) {
            throw new RuntimeException("Erro ao inicializar schema do banco", e);
        }

        // Migracoes incrementais — seguras para re-execucao
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        // Agendamento avancado (Palm-style): tipo, fim e dias da semana
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN schedule_type TEXT NOT NULL DEFAULT 'SINGLE'");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN end_date TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN recurrence_days TEXT");
        // Categorias para checklist, estudos e ideias
        applyAlterIfMissing("ALTER TABLE checklist_items ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE study_sessions ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        // Horário, prioridade e status nas tarefas
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN start_time TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN end_time TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN priority TEXT NOT NULL DEFAULT 'NORMAL'");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN status TEXT NOT NULL DEFAULT 'PENDENTE'");
        // Protocolos: validade em dias
        applyAlterIfMissing("ALTER TABLE protocols ADD COLUMN validity_days INTEGER NOT NULL DEFAULT 0");
        // Ideias e Projetos: campos avancados (pipeline cientifico)
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN priority TEXT NOT NULL DEFAULT 'NORMAL'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN idea_type TEXT NOT NULL DEFAULT 'GERAL'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN impact_level TEXT NOT NULL DEFAULT 'MEDIO'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN feasibility INTEGER NOT NULL DEFAULT 3");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN estimated_hours INTEGER NOT NULL DEFAULT 0");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN start_date TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN target_date TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN methodology TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN next_actions TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN keywords TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN references_text TEXT");
        // Modo da seção Próximas Ações: 'text' ou 'checklist'
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN next_actions_mode TEXT NOT NULL DEFAULT 'text'");
        // Vendas e Estoque: suporte a materiais e serviços
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN item_type TEXT NOT NULL DEFAULT 'material'");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN client_name TEXT");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN notes TEXT");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN status TEXT NOT NULL DEFAULT 'recebido'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN item_type TEXT NOT NULL DEFAULT 'material'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN unit_price REAL NOT NULL DEFAULT 0");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN description TEXT");
        // Checklist de Ideias/Projetos: coluna Kanban
        applyAlterIfMissing("ALTER TABLE idea_checklist_items ADD COLUMN kanban_column TEXT NOT NULL DEFAULT 'backlog'");
        // Checklist de Tarefas da Agenda: coluna kanban (já na tabela, mas garante compatibilidade)
        applyAlterIfMissing("ALTER TABLE task_checklist_items ADD COLUMN kanban_column TEXT NOT NULL DEFAULT 'backlog'");
    }

    private void applyAlterIfMissing(String alterSql) {
        try (Connection conn = connect(); Statement stmt = conn.createStatement()) {
            stmt.execute(alterSql);
        } catch (SQLException ignored) { /* coluna ja existe — ignorar */ }
    }
}

package com.pessoal.agenda.infra;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.sql.*;

/**
 * Infraestrutura de banco de dados SQLite.
 * Responsavel por fornecer conexoes e executar a migracao de schema.
 * Todos os repositorios dependem desta classe.
 */
public class Database {

    private final String jdbcUrl;

    public Database() {
        this.jdbcUrl = resolveJdbcUrl();
    }

    private String resolveJdbcUrl() {
        Path appDir = Path.of(System.getProperty("user.home"), ".agenda-pessoal");
        try {
            Files.createDirectories(appDir);
        } catch (IOException e) {
            throw new RuntimeException("Nao foi possivel criar diretorio de dados", e);
        }
        return "jdbc:sqlite:" + appDir.resolve("agenda.db");
    }

    /** Abre uma nova conexao JDBC. O chamador e responsavel por fechar. */
    public Connection connect() throws SQLException {
        return DriverManager.getConnection(jdbcUrl);
    }

    // ── Helpers compartilhados por repositorios ────────────────────────────

    /** Executa um UPDATE/INSERT/DELETE com parametros posicionais. */
    public void execute(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            ps.executeUpdate();
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao executar SQL: " + sql, e);
        }
    }

    /** Executa um SELECT e retorna o primeiro inteiro da primeira linha. */
    public int queryInt(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next() ? rs.getInt(1) : 0;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao consultar (int): " + sql, e);
        }
    }

    /** Executa um SELECT e retorna o primeiro double da primeira linha. */
    public double queryDouble(String sql, Object... params) {
        try (Connection conn = connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            bindParams(ps, params);
            try (ResultSet rs = ps.executeQuery()) {
                return rs.next() ? rs.getDouble(1) : 0.0;
            }
        } catch (SQLException e) {
            throw new RuntimeException("Erro ao consultar (double): " + sql, e);
        }
    }

    private void bindParams(PreparedStatement ps, Object[] params) throws SQLException {
        for (int i = 0; i < params.length; i++) ps.setObject(i + 1, params[i]);
    }

    // ── Migracao de schema ─────────────────────────────────────────────────

    /** Cria tabelas e aplica migrações incrementais. Idempotente. */
    public void runMigrations() {
        try (Connection conn = connect(); Statement stmt = conn.createStatement()) {
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS tasks (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    notes TEXT,
                    due_date TEXT NOT NULL,
                    done INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    protocol_name TEXT NOT NULL,
                    item_text TEXT NOT NULL,
                    done INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS finance_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    entry_type TEXT NOT NULL,
                    description TEXT NOT NULL,
                    amount REAL NOT NULL,
                    due_date TEXT,
                    paid INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS sales_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    product_name TEXT NOT NULL,
                    quantity INTEGER NOT NULL,
                    unit_price REAL NOT NULL,
                    sale_date TEXT NOT NULL,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS inventory_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    product_name TEXT NOT NULL,
                    quantity INTEGER NOT NULL,
                    minimum_quantity INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_sessions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    subject TEXT NOT NULL,
                    session_date TEXT NOT NULL,
                    duration_minutes INTEGER NOT NULL,
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS project_ideas (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    description TEXT,
                    status TEXT NOT NULL,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // Tabela de categorias personalizadas por dominio
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS categories (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    domain TEXT NOT NULL,
                    color TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    UNIQUE(name, domain)
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_plans (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    study_type TEXT NOT NULL DEFAULT 'GERAL',
                    category TEXT NOT NULL DEFAULT 'Geral',
                    description TEXT,
                    start_date TEXT,
                    target_date TEXT,
                    status TEXT NOT NULL DEFAULT 'PLANEJADO',
                    total_pages INTEGER NOT NULL DEFAULT 0,
                    current_page INTEGER NOT NULL DEFAULT 0,
                    progress_percent REAL NOT NULL DEFAULT 0.0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_entries (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_id INTEGER NOT NULL,
                    entry_title TEXT,
                    entry_date TEXT NOT NULL,
                    content TEXT,
                    duration_minutes INTEGER NOT NULL DEFAULT 0,
                    page_start INTEGER NOT NULL DEFAULT 0,
                    page_end INTEGER NOT NULL DEFAULT 0,
                    entry_order INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // ── Protocolos Operacionais ────────────────────────────────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocols (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    execution_type TEXT NOT NULL DEFAULT 'RECORRENTE',
                    category TEXT NOT NULL DEFAULT 'Geral',
                    description TEXT,
                    linked_task_id INTEGER,
                    validity_days INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_steps (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    template_id INTEGER NOT NULL,
                    step_order INTEGER NOT NULL DEFAULT 0,
                    step_text TEXT NOT NULL,
                    notes TEXT,
                    critical INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_executions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    template_id INTEGER NOT NULL,
                    iteration_number INTEGER NOT NULL DEFAULT 1,
                    started_at TEXT NOT NULL,
                    completed_at TEXT,
                    status TEXT NOT NULL DEFAULT 'ATIVA',
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS protocol_execution_steps (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    execution_id INTEGER NOT NULL,
                    step_id INTEGER NOT NULL,
                    step_text TEXT NOT NULL,
                    step_notes TEXT,
                    critical INTEGER NOT NULL DEFAULT 0,
                    step_order INTEGER NOT NULL DEFAULT 0,
                    checked INTEGER NOT NULL DEFAULT 0,
                    checked_at TEXT,
                    observation_notes TEXT,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // Protocolos: validade em dias (coluna pode já existir)
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_schedules (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_plan_id INTEGER NOT NULL,
                    day_of_week INTEGER NOT NULL,
                    min_minutes INTEGER NOT NULL DEFAULT 30,
                    UNIQUE(study_plan_id, day_of_week)
                )""");

            stmt.execute("""
                CREATE TABLE IF NOT EXISTS study_compensations (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    study_plan_id INTEGER NOT NULL,
                    missed_date TEXT NOT NULL,
                    compensation_date TEXT,
                    compensation_minutes INTEGER NOT NULL DEFAULT 0,
                    status TEXT NOT NULL DEFAULT 'PENDENTE',
                    notes TEXT,
                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
                )""");

            // ── Checklist de Próximas Ações (Ideias / Projetos) ───────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS idea_checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    idea_id INTEGER NOT NULL,
                    text TEXT NOT NULL DEFAULT '',
                    done INTEGER NOT NULL DEFAULT 0,
                    position INTEGER NOT NULL DEFAULT 0,
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

            // ── Checklist de Tarefas da Agenda ─────────────────────────────
            stmt.execute("""
                CREATE TABLE IF NOT EXISTS task_checklist_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    task_id INTEGER NOT NULL,
                    text TEXT NOT NULL DEFAULT '',
                    done INTEGER NOT NULL DEFAULT 0,
                    position INTEGER NOT NULL DEFAULT 0,
                    kanban_column TEXT NOT NULL DEFAULT 'backlog',
                    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
                )""");

        } catch (SQLException e) {
            throw new RuntimeException("Erro ao inicializar schema do banco", e);
        }

        // Migracoes incrementais — seguras para re-execucao
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        // Agendamento avancado (Palm-style): tipo, fim e dias da semana
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN schedule_type TEXT NOT NULL DEFAULT 'SINGLE'");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN end_date TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN recurrence_days TEXT");
        // Categorias para checklist, estudos e ideias
        applyAlterIfMissing("ALTER TABLE checklist_items ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE study_sessions ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        // Horário, prioridade e status nas tarefas
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN start_time TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN end_time TEXT");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN priority TEXT NOT NULL DEFAULT 'NORMAL'");
        applyAlterIfMissing("ALTER TABLE tasks ADD COLUMN status TEXT NOT NULL DEFAULT 'PENDENTE'");
        // Protocolos: validade em dias
        applyAlterIfMissing("ALTER TABLE protocols ADD COLUMN validity_days INTEGER NOT NULL DEFAULT 0");
        // Ideias e Projetos: campos avancados (pipeline cientifico)
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN priority TEXT NOT NULL DEFAULT 'NORMAL'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN idea_type TEXT NOT NULL DEFAULT 'GERAL'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN impact_level TEXT NOT NULL DEFAULT 'MEDIO'");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN feasibility INTEGER NOT NULL DEFAULT 3");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN estimated_hours INTEGER NOT NULL DEFAULT 0");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN start_date TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN target_date TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN methodology TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN next_actions TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN keywords TEXT");
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN references_text TEXT");
        // Modo da seção Próximas Ações: 'text' ou 'checklist'
        applyAlterIfMissing("ALTER TABLE project_ideas ADD COLUMN next_actions_mode TEXT NOT NULL DEFAULT 'text'");
        // Vendas e Estoque: suporte a materiais e serviços
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN item_type TEXT NOT NULL DEFAULT 'material'");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN client_name TEXT");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN notes TEXT");
        applyAlterIfMissing("ALTER TABLE sales_entries ADD COLUMN status TEXT NOT NULL DEFAULT 'recebido'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN item_type TEXT NOT NULL DEFAULT 'material'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN unit_price REAL NOT NULL DEFAULT 0");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN category TEXT NOT NULL DEFAULT 'Geral'");
        applyAlterIfMissing("ALTER TABLE inventory_items ADD COLUMN description TEXT");
        // Checklist de Ideias/Projetos: coluna Kanban
        applyAlterIfMissing("ALTER TABLE idea_checklist_items ADD COLUMN kanban_column TEXT NOT NULL DEFAULT 'backlog'");
        // Checklist de Tarefas da Agenda: coluna kanban (já na tabela, mas garante compatibilidade)
        applyAlterIfMissing("ALTER TABLE task_checklist_items ADD COLUMN kanban_column TEXT NOT NULL DEFAULT 'backlog'");

        // Google Tasks: tabela de mapeamento local ↔ Google
        applyCreateIfMissing("""
            CREATE TABLE IF NOT EXISTS google_tasks_mapping (
                id             INTEGER PRIMARY KEY AUTOINCREMENT,
                local_task_id  INTEGER NOT NULL,
                google_list_id TEXT    NOT NULL,
                google_task_id TEXT    NOT NULL,
                last_synced_at TEXT    NOT NULL DEFAULT (datetime('now')),
                UNIQUE(local_task_id),
                UNIQUE(google_list_id, google_task_id)
            )""");
    }

    /** Executa CREATE TABLE IF NOT EXISTS — usa o mesmo mecanismo idempotente. */
    private void applyCreateIfMissing(String createSql) {
        try (Connection conn = connect(); Statement stmt = conn.createStatement()) {
            stmt.execute(createSql);
        } catch (SQLException ignored) { /* já existe */ }
    }

    private void applyAlterIfMissing(String alterSql) {
        try (Connection conn = connect(); Statement stmt = conn.createStatement()) {
            stmt.execute(alterSql);
        } catch (SQLException ignored) { /* coluna ja existe — ignorar */ }
    }
}

package com.pessoal.agenda.repository;

import com.pessoal.agenda.infra.Database;

import java.sql.*;
import java.util.Optional;

/**
 * Repositório da tabela de mapeamento entre tarefas locais e Google Tasks.
 *
 * Tabela: google_tasks_mapping
 *   local_task_id  — FK para tasks.id
 *   google_list_id — ID da lista no Google Tasks
 *   google_task_id — ID da tarefa no Google Tasks
 *   last_synced_at — ISO-8601
 */
public class GoogleTasksMappingRepository {

    public record TaskMapping(long id, long localTaskId, String googleListId, String googleTaskId) {}

    private final Database db;

    public GoogleTasksMappingRepository(Database db) {
        this.db = db;
    }

    public Optional<TaskMapping> findByLocalId(long localTaskId) {
        String sql = "SELECT * FROM google_tasks_mapping WHERE local_task_id = ?";
        try (Connection conn = db.connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setLong(1, localTaskId);
            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) return Optional.of(map(rs));
            }
        } catch (SQLException e) { throw new RuntimeException("Erro ao buscar mapeamento", e); }
        return Optional.empty();
    }

    public Optional<TaskMapping> findByGoogleId(String googleListId, String googleTaskId) {
        String sql = "SELECT * FROM google_tasks_mapping WHERE google_list_id = ? AND google_task_id = ?";
        try (Connection conn = db.connect(); PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, googleListId);
            ps.setString(2, googleTaskId);
            try (ResultSet rs = ps.executeQuery()) {
                if (rs.next()) return Optional.of(map(rs));
            }
        } catch (SQLException e) { throw new RuntimeException("Erro ao buscar mapeamento", e); }
        return Optional.empty();
    }

    /** Cria ou atualiza mapeamento e registra horário de sync. */
    public void upsert(long localTaskId, String googleListId, String googleTaskId) {
        db.execute("""
            INSERT INTO google_tasks_mapping(local_task_id, google_list_id, google_task_id, last_synced_at)
            VALUES(?, ?, ?, datetime('now'))
            ON CONFLICT(local_task_id) DO UPDATE SET
                google_list_id  = excluded.google_list_id,
                google_task_id  = excluded.google_task_id,
                last_synced_at  = excluded.last_synced_at
            """, localTaskId, googleListId, googleTaskId);
    }

    public void deleteByLocalId(long localTaskId) {
        db.execute("DELETE FROM google_tasks_mapping WHERE local_task_id = ?", localTaskId);
    }

    public void deleteByGoogleId(String googleListId, String googleTaskId) {
        db.execute("DELETE FROM google_tasks_mapping WHERE google_list_id=? AND google_task_id=?",
                googleListId, googleTaskId);
    }

    private TaskMapping map(ResultSet rs) throws SQLException {
        return new TaskMapping(
                rs.getLong("id"),
                rs.getLong("local_task_id"),
                rs.getString("google_list_id"),
                rs.getString("google_task_id"));
    }
}

package com.pessoal.agenda.service;

import java.awt.Desktop;
import java.io.*;
import java.net.*;
import java.net.http.*;
import java.net.http.HttpResponse.BodyHandlers;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.time.Instant;
import java.util.function.Consumer;

/**
 * Gerencia a autenticação OAuth 2.0 com o Google (fluxo Desktop App).
 *
 * Credenciais lidas de: ~/.agenda/google-credentials.json
 * Tokens armazenados em: ~/.agenda/google-tokens.json
 *
 * Fluxo:
 *   1. Gera URL de autorização
 *   2. Abre o navegador
 *   3. Escuta em porta local (ServerSocket) para capturar o callback
 *   4. Troca o código por access_token + refresh_token
 *   5. Salva tokens localmente
 */
public class GoogleAuthService {

    private static final String CREDENTIALS_PATH =
            System.getProperty("user.home") + "/.agenda/google-credentials.json";
    private static final String TOKENS_PATH =
            System.getProperty("user.home") + "/.agenda/google-tokens.json";

    private static final String SCOPE =
            "https://www.googleapis.com/auth/tasks";

    // Credenciais lidas do arquivo
    private String clientId;
    private String clientSecret;
    private String tokenUri;
    private String authUri;

    // Tokens em memória
    private String accessToken;
    private String refreshToken;
    private long   expiresAt; // epoch seconds

    private static GoogleAuthService INSTANCE;

    private GoogleAuthService() {
        loadCredentials();
        loadTokens();
    }

    public static synchronized GoogleAuthService getInstance() {
        if (INSTANCE == null) INSTANCE = new GoogleAuthService();
        return INSTANCE;
    }

    // ── Estado ──────────────────────────────────────────────────────────────

    public boolean isAuthorized() {
        return refreshToken != null && !refreshToken.isBlank();
    }

    public boolean hasValidCredentials() {
        return clientId != null && !clientId.isBlank();
    }

    /** Revoga a autorização e remove tokens locais. */
    public void revoke() throws IOException {
        accessToken  = null;
        refreshToken = null;
        expiresAt    = 0;
        Files.deleteIfExists(Paths.get(TOKENS_PATH));
    }

    // ── Token de acesso ──────────────────────────────────────────────────────

    /**
     * Retorna um access token válido.
     * Refresca automaticamente se expirado.
     * @throws IllegalStateException se não autorizado
     */
    public synchronized String getAccessToken() throws IOException, InterruptedException {
        if (!isAuthorized()) throw new IllegalStateException("Não autorizado. Realize a conexão primeiro.");
        long now = Instant.now().getEpochSecond();
        if (accessToken == null || now >= expiresAt - 60) {
            refreshAccessToken();
        }
        return accessToken;
    }

    // ── Fluxo de autorização ────────────────────────────────────────────────

    /**
     * Inicia o fluxo de autorização OAuth 2.0.
     * Abre o navegador e aguarda o callback.
     *
     * @param progressCallback callback chamado com mensagens de progresso (para UI)
     * @throws Exception em caso de erro
     */
    public void authorize(Consumer<String> progressCallback) throws Exception {
        if (!hasValidCredentials()) {
            throw new IllegalStateException(
                "Credenciais não encontradas em: " + CREDENTIALS_PATH);
        }

        // Porta dinâmica
        int callbackPort;
        try (ServerSocket probe = new ServerSocket(0)) {
            callbackPort = probe.getLocalPort();
        }
        String redirectUri = "http://localhost:" + callbackPort;

        String authUrl = authUri + "?"
                + "client_id=" + URLEncoder.encode(clientId, StandardCharsets.UTF_8)
                + "&redirect_uri=" + URLEncoder.encode(redirectUri, StandardCharsets.UTF_8)
                + "&response_type=code"
                + "&scope=" + URLEncoder.encode(SCOPE, StandardCharsets.UTF_8)
                + "&access_type=offline"
                + "&prompt=consent";

        if (progressCallback != null) progressCallback.accept("Abrindo navegador para autorização...");

        if (Desktop.isDesktopSupported()) {
            Desktop.getDesktop().browse(new URI(authUrl));
        } else {
            throw new UnsupportedOperationException(
                "Não foi possível abrir o navegador. Acesse manualmente:\n" + authUrl);
        }

        // Aguarda callback
        if (progressCallback != null) progressCallback.accept("Aguardando autorização do Google...");
        String code = waitForAuthCode(callbackPort, redirectUri);

        if (progressCallback != null) progressCallback.accept("Trocando código por tokens...");
        exchangeCodeForTokens(code, redirectUri);

        if (progressCallback != null) progressCallback.accept("Conectado com sucesso!");
    }

    // ── Internals ────────────────────────────────────────────────────────────

    private String waitForAuthCode(int port, String redirectUri) throws Exception {
        try (ServerSocket server = new ServerSocket(port)) {
            server.setSoTimeout(120_000); // 2 minutos
            try (Socket client = server.accept()) {
                // Lê a primeira linha do request: GET /?code=xxx&... HTTP/1.1
                BufferedReader reader = new BufferedReader(
                        new InputStreamReader(client.getInputStream(), StandardCharsets.UTF_8));
                String requestLine = reader.readLine();

                // Responde com HTML de sucesso
                String html = "<!DOCTYPE html><html><head><meta charset='UTF-8'>"
                        + "<title>Autorizado</title></head><body style='font-family:sans-serif;"
                        + "text-align:center;padding:60px;'>"
                        + "<h2 style='color:#1a73e8'>✓ Conexão realizada com sucesso!</h2>"
                        + "<p>Você pode fechar esta aba e voltar para a Agenda Científica.</p>"
                        + "</body></html>";
                String response = "HTTP/1.1 200 OK\r\n"
                        + "Content-Type: text/html; charset=UTF-8\r\n"
                        + "Content-Length: " + html.getBytes(StandardCharsets.UTF_8).length + "\r\n"
                        + "Connection: close\r\n\r\n" + html;
                client.getOutputStream().write(response.getBytes(StandardCharsets.UTF_8));

                if (requestLine == null || !requestLine.contains("code=")) {
                    throw new IOException("Callback sem código de autorização: " + requestLine);
                }

                // Extrai o code da query string: /  ?code=XXXX&scope=...
                String query = requestLine.split(" ")[1];
                if (query.contains("?")) query = query.substring(query.indexOf('?') + 1);
                for (String param : query.split("&")) {
                    if (param.startsWith("code=")) {
                        return URLDecoder.decode(param.substring(5), StandardCharsets.UTF_8);
                    }
                }
                throw new IOException("Parâmetro 'code' não encontrado na resposta: " + requestLine);
            }
        }
    }

    private void exchangeCodeForTokens(String code, String redirectUri)
            throws IOException, InterruptedException {
        String body = "grant_type=authorization_code"
                + "&code=" + URLEncoder.encode(code, StandardCharsets.UTF_8)
                + "&client_id=" + URLEncoder.encode(clientId, StandardCharsets.UTF_8)
                + "&client_secret=" + URLEncoder.encode(clientSecret, StandardCharsets.UTF_8)
                + "&redirect_uri=" + URLEncoder.encode(redirectUri, StandardCharsets.UTF_8);

        String response = post(tokenUri, body);
        parseAndSaveTokens(response);
    }

    private synchronized void refreshAccessToken() throws IOException, InterruptedException {
        if (refreshToken == null) throw new IllegalStateException("Sem refresh token.");
        String body = "grant_type=refresh_token"
                + "&refresh_token=" + URLEncoder.encode(refreshToken, StandardCharsets.UTF_8)
                + "&client_id=" + URLEncoder.encode(clientId, StandardCharsets.UTF_8)
                + "&client_secret=" + URLEncoder.encode(clientSecret, StandardCharsets.UTF_8);
        String response = post(tokenUri, body);
        // Refresh response: access_token + expires_in (sem new refresh_token geralmente)
        String newAccess  = SimpleJson.str(response, "access_token");
        long   expiresIn  = SimpleJson.num(response, "expires_in");
        String newRefresh = SimpleJson.str(response, "refresh_token");
        if (newAccess == null) throw new IOException("Falha ao renovar token: " + response);
        accessToken = newAccess;
        expiresAt   = Instant.now().getEpochSecond() + (expiresIn > 0 ? expiresIn : 3600);
        if (newRefresh != null && !newRefresh.isBlank()) refreshToken = newRefresh;
        saveTokens();
    }

    private void parseAndSaveTokens(String response) throws IOException {
        accessToken  = SimpleJson.str(response, "access_token");
        refreshToken = SimpleJson.str(response, "refresh_token");
        long expiresIn = SimpleJson.num(response, "expires_in");
        if (accessToken == null || refreshToken == null) {
            throw new IOException("Resposta de token inválida: " + response);
        }
        expiresAt = Instant.now().getEpochSecond() + (expiresIn > 0 ? expiresIn : 3600);
        saveTokens();
    }

    private void saveTokens() throws IOException {
        Path path = Paths.get(TOKENS_PATH);
        String json = "{\"access_token\":\"" + accessToken + "\","
                    + "\"refresh_token\":\"" + refreshToken + "\","
                    + "\"expires_at\":" + expiresAt + "}";
        Files.writeString(path, json, StandardCharsets.UTF_8);
    }

    private void loadTokens() {
        try {
            Path path = Paths.get(TOKENS_PATH);
            if (!Files.exists(path)) return;
            String json = Files.readString(path, StandardCharsets.UTF_8);
            accessToken  = SimpleJson.str(json, "access_token");
            refreshToken = SimpleJson.str(json, "refresh_token");
            expiresAt    = SimpleJson.num(json, "expires_at");
        } catch (IOException e) {
            // tokens inexistentes ou corrompidos – ignorar
        }
    }

    private void loadCredentials() {
        try {
            Path path = Paths.get(CREDENTIALS_PATH);
            if (!Files.exists(path)) return;
            String json = Files.readString(path, StandardCharsets.UTF_8);
            // JSON: {"installed":{"client_id":"...","client_secret":"...","auth_uri":"...","token_uri":"..."}}
            String installed = extractObject(json, "installed");
            if (installed == null) installed = json; // fallback
            clientId     = SimpleJson.str(installed, "client_id");
            clientSecret = SimpleJson.str(installed, "client_secret");
            tokenUri     = SimpleJson.str(installed, "token_uri");
            authUri      = SimpleJson.str(installed, "auth_uri");
        } catch (IOException e) {
            System.err.println("[GoogleAuth] Erro ao ler credenciais: " + e.getMessage());
        }
    }

    /** Extrai o conteúdo do objeto para "key": {...} */
    private static String extractObject(String json, String key) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return null;
        idx = json.indexOf('{', idx);
        if (idx < 0) return null;
        int depth = 0, start = idx;
        while (idx < json.length()) {
            char c = json.charAt(idx);
            if      (c == '{') depth++;
            else if (c == '}') { depth--; if (depth == 0) return json.substring(start, idx + 1); }
            idx++;
        }
        return null;
    }

    /** HTTP POST com Content-Type: application/x-www-form-urlencoded */
    private static String post(String url, String body) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .header("Content-Type", "application/x-www-form-urlencoded")
                .POST(HttpRequest.BodyPublishers.ofString(body, StandardCharsets.UTF_8))
                .build();
        HttpResponse<String> response = client.send(request, BodyHandlers.ofString());
        return response.body();
    }
}

package com.pessoal.agenda.service;

import com.pessoal.agenda.repository.GoogleTasksMappingRepository;
import com.pessoal.agenda.repository.GoogleTasksMappingRepository.TaskMapping;
import com.pessoal.agenda.repository.TaskRepository;

import java.io.IOException;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.*;
import java.net.http.HttpResponse.BodyHandlers;
import java.nio.charset.StandardCharsets;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.stream.Collectors;

/**
 * Integração com o Google Tasks REST API v1.
 *
 * Referência: https://developers.google.com/tasks/reference/rest
 */
public class GoogleTasksService {

    private static final String BASE = "https://tasks.googleapis.com/tasks/v1";

    private final GoogleAuthService auth;
    private final HttpClient        http;

    public GoogleTasksService() {
        this.auth = GoogleAuthService.getInstance();
        this.http = HttpClient.newHttpClient();
    }

    // ── Modelos ──────────────────────────────────────────────────────────────

    public record TaskList(String id, String title) {
        @Override public String toString() { return title; }
    }

    public record GTask(String id, String title, String notes,
                        String due,   // ISO-8601 datetime ou null
                        boolean completed, String status) {
        /** Data de vencimento extraída ou null */
        public LocalDate dueDate() {
            if (due == null || due.isBlank()) return null;
            try { return LocalDate.parse(due.substring(0, 10)); }
            catch (Exception e) { return null; }
        }
        @Override public String toString() { return title != null ? title : "(sem título)"; }
    }

    /**
     * Resultado de um ciclo de sincronização bidirecional.
     * @param createdLocal    tarefas criadas localmente (vieram do Google)
     * @param createdGoogle   tarefas criadas no Google (vieram do local)
     * @param completedLocal  tarefas marcadas como concluídas localmente
     * @param completedGoogle tarefas marcadas como concluídas no Google
     * @param errors          número de erros não fatais
     * @param log             mensagens de log legíveis
     */
    public record SyncResult(int createdLocal, int createdGoogle,
                              int completedLocal, int completedGoogle,
                              int errors, List<String> log) {
        public boolean hasChanges() {
            return createdLocal + createdGoogle + completedLocal + completedGoogle > 0;
        }
    }

    // ── Task Lists ───────────────────────────────────────────────────────────

    /** Lista todas as listas de tarefas do usuário. */
    public List<TaskList> listTaskLists() throws IOException, InterruptedException {
        String json = get("/users/@me/lists");
        List<String> items = SimpleJson.array(json, "items");
        List<TaskList> result = new ArrayList<>();
        for (String item : items) {
            String id    = SimpleJson.str(item, "id");
            String title = SimpleJson.str(item, "title");
            if (id != null) result.add(new TaskList(id, title != null ? title : "(sem nome)"));
        }
        return result;
    }

    // ── Tasks ────────────────────────────────────────────────────────────────

    /**
     * Lista tarefas de uma lista específica.
     *
     * @param taskListId   ID da lista Google Tasks
     * @param showCompleted incluir tarefas concluídas
     */
    public List<GTask> listTasks(String taskListId, boolean showCompleted)
            throws IOException, InterruptedException {
        String url = "/lists/" + encode(taskListId) + "/tasks"
                   + "?showCompleted=" + showCompleted
                   + "&maxResults=100";
        String json = get(url);
        List<String> items = SimpleJson.array(json, "items");
        List<GTask> result = new ArrayList<>();
        for (String item : items) {
            String id        = SimpleJson.str(item, "id");
            String title     = SimpleJson.str(item, "title");
            String notes     = SimpleJson.str(item, "notes");
            String due       = SimpleJson.str(item, "due");
            String status    = SimpleJson.str(item, "status");
            boolean done     = "completed".equalsIgnoreCase(status);
            if (id != null) result.add(new GTask(id, title, notes, due, done, status));
        }
        return result;
    }

    /**
     * Cria uma nova tarefa em uma lista.
     *
     * @param taskListId ID da lista
     * @param title      título
     * @param notes      notas (pode ser null)
     * @param dueDate    data de vencimento (pode ser null)
     * @return ID da tarefa criada
     */
    public String createTask(String taskListId, String title, String notes, LocalDate dueDate)
            throws IOException, InterruptedException {
        String due = dueDate != null ? dueDate + "T00:00:00.000Z" : null;
        String body = buildTaskJson(title, notes, due, false);
        String response = post("/lists/" + encode(taskListId) + "/tasks", body);
        return SimpleJson.str(response, "id");
    }

    /**
     * Marca uma tarefa como concluída.
     */
    public void completeTask(String taskListId, String taskId)
            throws IOException, InterruptedException {
        String body = "{\"status\":\"completed\"}";
        patch("/lists/" + encode(taskListId) + "/tasks/" + encode(taskId), body);
    }

    /**
     * Reabre uma tarefa concluída (marca como needsAction).
     */
    public void reopenTask(String taskListId, String taskId)
            throws IOException, InterruptedException {
        String body = "{\"status\":\"needsAction\",\"completed\":null}";
        patch("/lists/" + encode(taskListId) + "/tasks/" + encode(taskId), body);
    }

    /**
     * Deleta uma tarefa.
     */
    public void deleteTask(String taskListId, String taskId)
            throws IOException, InterruptedException {
        delete("/lists/" + encode(taskListId) + "/tasks/" + encode(taskId));
    }

    /**
     * Atualiza o título e notas de uma tarefa.
     */
    public void updateTask(String taskListId, String taskId,
                           String title, String notes, LocalDate dueDate)
            throws IOException, InterruptedException {
        String due = dueDate != null ? dueDate + "T00:00:00.000Z" : null;
        String body = buildTaskJson(title, notes, due, false);
        patch("/lists/" + encode(taskListId) + "/tasks/" + encode(taskId), body);
    }

    // ── Sync Bidirecional ────────────────────────────────────────────────────

    /**
     * Executa sincronização bidirecional completa entre uma lista do Google Tasks
     * e as tarefas locais.
     *
     * Regras:
     *  - Google task sem mapeamento → cria localmente + salva mapeamento
     *  - Local task sem mapeamento  → cria no Google + salva mapeamento
     *  - Concluída no Google e não localmente → conclui localmente
     *  - Concluída localmente e não no Google → conclui no Google
     *  - Título/notas locais → atualiza no Google (local é fonte de verdade para texto)
     */
    public SyncResult syncBidirectional(String googleListId,
                                        TaskRepository taskRepo,
                                        GoogleTasksMappingRepository mappingRepo)
            throws IOException, InterruptedException {

        List<String> log = new ArrayList<>();
        int createdLocal = 0, createdGoogle = 0, completedLocal = 0, completedGoogle = 0, errors = 0;

        // Busca todos os dados
        List<GTask> googleTasks = listTasks(googleListId, true);
        List<com.pessoal.agenda.model.Task> localTasks = taskRepo.findOpenTasks();

        // Indexa as tarefas do Google por ID
        Map<String, GTask> googleById = googleTasks.stream()
                .collect(Collectors.toMap(GTask::id, t -> t));

        // ── PASSO 1: para cada tarefa do Google ──────────────────────────────
        for (GTask gt : googleTasks) {
            try {
                Optional<TaskMapping> mapping = mappingRepo.findByGoogleId(googleListId, gt.id());

                if (mapping.isEmpty()) {
                    // Nova no Google → cria localmente
                    LocalDate due = gt.dueDate() != null ? gt.dueDate() : LocalDate.now();
                    taskRepo.save(gt.title(),
                            gt.notes() != null && !gt.notes().isBlank() ? gt.notes() : null,
                            due, "Google Tasks");
                    // Recupera o ID recém-inserido
                    List<com.pessoal.agenda.model.Task> all = taskRepo.findOpenTasks();
                    com.pessoal.agenda.model.Task created = all.stream()
                            .filter(t -> t.title().equals(gt.title()))
                            .reduce((a, b) -> b) // pega o mais recente
                            .orElse(null);
                    if (created != null) {
                        mappingRepo.upsert(created.id(), googleListId, gt.id());
                        if (gt.completed()) {
                            taskRepo.markDone(created.id());
                            completedLocal++;
                        }
                    }
                    createdLocal++;
                    log.add("⬇ Criado local: " + gt.title());
                } else {
                    // Mapeamento existe → sincroniza status de conclusão
                    long localId = mapping.get().localTaskId();
                    com.pessoal.agenda.model.Task local = taskRepo.findById(localId).orElse(null);

                    if (local != null) {
                        // Google concluiu → conclui localmente
                        if (gt.completed() && !local.done()) {
                            taskRepo.markDone(localId);
                            completedLocal++;
                            log.add("✓ Concluído local (Google): " + gt.title());
                        }
                        // Local concluiu → conclui no Google
                        if (local.done() && !gt.completed()) {
                            completeTask(googleListId, gt.id());
                            completedGoogle++;
                            log.add("✓ Concluído Google (local): " + local.title());
                        }
                        // Atualiza texto no Google com dados locais (local é fonte de verdade)
                        if (!local.done() && !gt.completed()) {
                            updateTask(googleListId, gt.id(),
                                    local.title(), local.notes(), local.dueDate());
                        }
                        mappingRepo.upsert(localId, googleListId, gt.id());
                    }
                }
            } catch (Exception e) {
                errors++;
                log.add("✗ Erro em '" + gt.title() + "': " + e.getMessage());
            }
        }

        // ── PASSO 2: para cada tarefa local sem mapeamento → cria no Google ──
        for (com.pessoal.agenda.model.Task local : localTasks) {
            if (local.done()) continue; // não exporta tarefas já concluídas
            try {
                if (mappingRepo.findByLocalId(local.id()).isEmpty()) {
                    String gId = createTask(googleListId, local.title(),
                            local.notes(), local.dueDate());
                    if (gId != null) {
                        mappingRepo.upsert(local.id(), googleListId, gId);
                        createdGoogle++;
                        log.add("⬆ Criado Google: " + local.title());
                    }
                }
            } catch (Exception e) {
                errors++;
                log.add("✗ Erro ao exportar '" + local.title() + "': " + e.getMessage());
            }
        }

        return new SyncResult(createdLocal, createdGoogle, completedLocal, completedGoogle,
                errors, log);
    }

    // ── HTTP helpers ─────────────────────────────────────────────────────────

    private String get(String path) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(BASE + path))
                .header("Authorization", "Bearer " + auth.getAccessToken())
                .GET()
                .build();
        HttpResponse<String> res = http.send(req, BodyHandlers.ofString());
        checkStatus(res);
        return res.body();
    }

    private String post(String path, String jsonBody) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(BASE + path))
                .header("Authorization", "Bearer " + auth.getAccessToken())
                .header("Content-Type", "application/json; charset=UTF-8")
                .POST(HttpRequest.BodyPublishers.ofString(jsonBody, StandardCharsets.UTF_8))
                .build();
        HttpResponse<String> res = http.send(req, BodyHandlers.ofString());
        checkStatus(res);
        return res.body();
    }

    private void patch(String path, String jsonBody) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(BASE + path))
                .header("Authorization", "Bearer " + auth.getAccessToken())
                .header("Content-Type", "application/json; charset=UTF-8")
                .method("PATCH", HttpRequest.BodyPublishers.ofString(jsonBody, StandardCharsets.UTF_8))
                .build();
        HttpResponse<String> res = http.send(req, BodyHandlers.ofString());
        checkStatus(res);
    }

    private void delete(String path) throws IOException, InterruptedException {
        HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(BASE + path))
                .header("Authorization", "Bearer " + auth.getAccessToken())
                .DELETE()
                .build();
        HttpResponse<String> res = http.send(req, BodyHandlers.ofString());
        if (res.statusCode() != 204 && res.statusCode() != 200) {
            throw new IOException("Google API DELETE falhou [" + res.statusCode() + "]: " + res.body());
        }
    }

    private static void checkStatus(HttpResponse<String> res) throws IOException {
        int code = res.statusCode();
        if (code < 200 || code >= 300) {
            throw new IOException("Google API error [" + code + "]: " + res.body());
        }
    }

    private static String buildTaskJson(String title, String notes, String due, boolean completed) {
        StringBuilder sb = new StringBuilder("{");
        sb.append("\"title\":\"").append(escapeJson(title != null ? title : "")).append("\"");
        if (notes != null && !notes.isBlank())
            sb.append(",\"notes\":\"").append(escapeJson(notes)).append("\"");
        if (due != null)
            sb.append(",\"due\":\"").append(due).append("\"");
        if (completed)
            sb.append(",\"status\":\"completed\"");
        sb.append("}");
        return sb.toString();
    }

    private static String escapeJson(String s) {
        return s.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private static String encode(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }
}

package com.pessoal.agenda.service;

import java.util.ArrayList;
import java.util.List;

/**
 * Parser JSON minimalista para respostas da Google API.
 * Suporta campos string/número de primeiro nível e arrays de objetos.
 */
public final class SimpleJson {

    private SimpleJson() {}

    /** Extrai o valor de um campo string: "key": "value" */
    public static String str(String json, String key) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return null;
        idx = json.indexOf(':', idx) + 1;
        while (idx < json.length() && Character.isWhitespace(json.charAt(idx))) idx++;
        if (idx >= json.length()) return null;
        char first = json.charAt(idx);
        if (first == '"') {
            // string value
            idx++;
            StringBuilder sb = new StringBuilder();
            while (idx < json.length()) {
                char c = json.charAt(idx++);
                if (c == '\\' && idx < json.length()) {
                    char esc = json.charAt(idx++);
                    switch (esc) {
                        case '"'  -> sb.append('"');
                        case '\\' -> sb.append('\\');
                        case 'n'  -> sb.append('\n');
                        case 'r'  -> sb.append('\r');
                        case 't'  -> sb.append('\t');
                        default   -> { sb.append('\\'); sb.append(esc); }
                    }
                } else if (c == '"') {
                    break;
                } else {
                    sb.append(c);
                }
            }
            return sb.toString();
        } else {
            // número, boolean ou null
            int end = idx;
            while (end < json.length() && ",}\n\r]".indexOf(json.charAt(end)) < 0) end++;
            return json.substring(idx, end).trim();
        }
    }

    /** Extrai valor long de um campo numérico. Retorna -1 se não encontrado. */
    public static long num(String json, String key) {
        String v = str(json, key);
        if (v == null) return -1;
        try { return Long.parseLong(v.trim()); }
        catch (NumberFormatException e) { return -1; }
    }

    /**
     * Extrai um array de objetos JSON: "key": [{...},{...}]
     * Retorna cada objeto como string JSON independente.
     */
    public static List<String> array(String json, String key) {
        int idx = json.indexOf("\"" + key + "\"");
        if (idx < 0) return List.of();
        idx = json.indexOf('[', idx);
        if (idx < 0) return List.of();
        idx++; // skip '['
        List<String> result = new ArrayList<>();
        while (idx < json.length()) {
            while (idx < json.length() && Character.isWhitespace(json.charAt(idx))) idx++;
            if (idx >= json.length()) break;
            char c = json.charAt(idx);
            if (c == ']') break;
            if (c == ',') { idx++; continue; }
            if (c == '{') {
                int depth = 0, start = idx;
                while (idx < json.length()) {
                    char ch = json.charAt(idx);
                    if      (ch == '{') depth++;
                    else if (ch == '}') { depth--; if (depth == 0) { idx++; break; } }
                    idx++;
                }
                result.add(json.substring(start, idx));
            } else {
                idx++;
            }
        }
        return result;
    }

    /** Verifica se um campo boolean é true */
    public static boolean bool(String json, String key) {
        String v = str(json, key);
        return "true".equalsIgnoreCase(v);
    }
}

package com.pessoal.agenda.ui.controller;

import com.pessoal.agenda.DatabaseService;
import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.app.SharedContext;
import com.pessoal.agenda.model.ScheduleType;
import com.pessoal.agenda.model.Task;
import com.pessoal.agenda.model.TaskPriority;
import com.pessoal.agenda.model.TaskStatus;
import com.pessoal.agenda.tools.ICalendarExporter;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Node;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.FileChooser;
import javafx.stage.Stage;

import java.io.File;
import java.io.IOException;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.YearMonth;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Locale;

/**
 * Controller da aba Agenda e Prioridades.
 *
 * Gerencia:
 *   – Visualizações por Dia / Semana / Mês / Ano
 *   – Formulário de criação e edição de tarefas (com recorrência Palm-style)
 *   – Navegação temporal
 *   – Painel lateral de ações
 */
public class AgendaTabController {

    private enum AgendaView { DIA, SEMANA, MES, ANO }

    private final SharedContext   ctx;
    private final DatabaseService db;

    // ── Estado de navegação ────────────────────────────────────────────────
    private AgendaView currentView   = AgendaView.MES;
    private LocalDate  currentDate   = LocalDate.now();
    private String     categoryFilter = null;

    // ── Referências de UI (área de conteúdo) ──────────────────────────────
    private VBox  contentArea;
    private Label periodLabel;
    private ListView<DatabaseService.RowItem> currentMainListView;

    // ── Listas de dados ────────────────────────────────────────────────────
    private final ObservableList<DatabaseService.RowItem>               taskItems    = FXCollections.observableArrayList();
    private final ObservableList<DatabaseService.RowItem>               dayTaskItems = FXCollections.observableArrayList();
    private final List<ObservableList<DatabaseService.RowItem>> weekDayItems = List.of(
            FXCollections.observableArrayList(), FXCollections.observableArrayList(),
            FXCollections.observableArrayList(), FXCollections.observableArrayList(),
            FXCollections.observableArrayList(), FXCollections.observableArrayList(),
            FXCollections.observableArrayList());

    // ── Campos do formulário ───────────────────────────────────────────────
    private Long             editingId       = null;
    private Label            formModeLabel;
    private Button           submitBtn;
    private Button           cancelEditBtn;
    private TextField        titleField;
    private ComboBox<String> catCombo;
    private ComboBox<String> priorityCombo;
    private ComboBox<String> statusCombo;
    private DatePicker       startPicker;
    private TextField        startTimeField;
    private TextField        endTimeField;
    private ComboBox<String> scheduleCombo;
    private DatePicker       endDatePicker;
    private CheckBox[]       dayChecks;
    private TextArea         notesArea;
    private Label            endDateLabel;
    private Label            daysLabel;
    private HBox             daysBox;

    public AgendaTabController(SharedContext ctx, DatabaseService db) {
        this.ctx = ctx;
        this.db  = db;
    }

    // ── API pública ────────────────────────────────────────────────────────

    public Tab buildTab() {
        Tab tab = new Tab("Agenda e Prioridades");
        tab.setClosable(false);

        // Listener para atualizar a lista principal quando o timer mudar de estado
        com.pessoal.agenda.service.TaskTimerService.get().addStateListener(this::refreshMainListView);

        // Adiciona CSS do timer inline
        var cssUrl = getClass().getResource("/com/pessoal/agenda/timer-inline.css");
        if (cssUrl != null) {
            // Aplica ao Scene se já existir, senão aplica ao contentArea depois
            if (tab.getContent() instanceof Region r && r.getScene() != null) {
                r.getScene().getStylesheets().add(cssUrl.toExternalForm());
            } else {
                // fallback: aplica ao contentArea quando disponível
                contentArea = new VBox();
                contentArea.getStylesheets().add(cssUrl.toExternalForm());
            }
        }

        // filtro de categoria
        ComboBox<String> catFilterCombo = new ComboBox<>();
        catFilterCombo.getStyleClass().add("input-control");
        catFilterCombo.getItems().add("Todas as categorias");
        ctx.taskCatNames.addListener((javafx.collections.ListChangeListener<String>) ch -> {
            String cur = catFilterCombo.getValue();
            catFilterCombo.getItems().setAll("Todas as categorias");
            catFilterCombo.getItems().addAll(ctx.taskCatNames);
            catFilterCombo.setValue(cur != null ? cur : "Todas as categorias");
        });
        catFilterCombo.setValue("Todas as categorias");
        catFilterCombo.setOnAction(e -> {
            String v = catFilterCombo.getValue();
            categoryFilter = "Todas as categorias".equals(v) ? null : v;
            refreshCurrentView();
        });

        // botões de visualização
        ToggleGroup viewGroup = new ToggleGroup();
        ToggleButton diaBtn    = buildViewToggle("Dia",    AgendaView.DIA,    viewGroup);
        ToggleButton semanaBtn = buildViewToggle("Semana", AgendaView.SEMANA, viewGroup);
        ToggleButton mesBtn    = buildViewToggle("Mês",    AgendaView.MES,    viewGroup);
        ToggleButton anoBtn    = buildViewToggle("Ano",    AgendaView.ANO,    viewGroup);
        mesBtn.setSelected(true);

        HBox viewToggleBar = new HBox(2, diaBtn, semanaBtn, mesBtn, anoBtn);
        viewToggleBar.getStyleClass().add("view-toggle-bar");

        // navegação temporal
        Button prevBtn  = new Button("‹"); prevBtn.getStyleClass().add("nav-button");
        prevBtn.setOnAction(e -> navigateBack());
        Button nextBtn  = new Button("›"); nextBtn.getStyleClass().add("nav-button");
        nextBtn.setOnAction(e -> navigateForward());
        Button todayBtn = new Button("Hoje"); todayBtn.getStyleClass().add("secondary-button");
        todayBtn.setOnAction(e -> { currentDate = LocalDate.now(); refreshCurrentView(); });

        periodLabel = new Label();
        periodLabel.getStyleClass().add("nav-period-label");

        HBox navBar = new HBox(6, prevBtn, periodLabel, nextBtn, todayBtn);
        navBar.setAlignment(Pos.CENTER_LEFT);

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox topBar = new HBox(12, new Label("Categoria:"), catFilterCombo,
                new Separator(), viewToggleBar, spacer, navBar);
        topBar.setAlignment(Pos.CENTER_LEFT);
        topBar.getStyleClass().add("agenda-top-bar");

        contentArea = new VBox();
        contentArea.getStyleClass().add("agenda-content-area");
        VBox.setVgrow(contentArea, Priority.ALWAYS);

        VBox mainPanel = new VBox(10, topBar, contentArea);
        VBox.setVgrow(contentArea, Priority.ALWAYS);
        mainPanel.setPadding(new Insets(14));
        HBox.setHgrow(mainPanel, Priority.ALWAYS);

        VBox sidePanel = buildSidePanel();
        sidePanel.setPrefWidth(370); sidePanel.setMinWidth(340);

        HBox content = new HBox(10, mainPanel, sidePanel);
        content.setPadding(new Insets(0, 14, 14, 0));
        tab.setContent(content);

        refreshCurrentView();
        return tab;
    }

    /** Atualiza a view atual da agenda (chamado pelo AgendaApp no refreshAllData). */
    public void refresh() {
        refreshCurrentView();
        ctx.alertItems.setAll(db.listDeadlineAlerts());
        ctx.upcomingItems.setAll(db.listUpcomingDeadlines(10));
    }

    public LocalDate getCurrentDate() { return currentDate; }

    // ── Painel lateral (formulário + ações) ────────────────────────────────

    private VBox buildSidePanel() {
        titleField = new TextField();
        titleField.getStyleClass().add("input-control");
        titleField.setPromptText("Título da tarefa");

        catCombo = new ComboBox<>();
        catCombo.getStyleClass().add("input-control");
        catCombo.setItems(ctx.taskCatNames);
        catCombo.setValue(ctx.taskCatNames.isEmpty() ? "Geral" : ctx.taskCatNames.get(0));

        priorityCombo = new ComboBox<>();
        priorityCombo.getStyleClass().add("input-control");
        for (TaskPriority p : TaskPriority.values()) priorityCombo.getItems().add(p.label());
