        form.add(endDateLabel,                0, row); form.add(endDatePicker, 1, row++);
        form.add(daysLabel,                   0, row); form.add(daysBox,       1, row++);
        form.add(new Label("Notas"),          0, row); form.add(notesArea,     1, row);
        GridPane.setHgrow(titleField,    Priority.ALWAYS);
        GridPane.setHgrow(catCombo,      Priority.ALWAYS);
        GridPane.setHgrow(priorityCombo, Priority.ALWAYS);
        GridPane.setHgrow(statusCombo,   Priority.ALWAYS);
        GridPane.setHgrow(startPicker,   Priority.ALWAYS);
        GridPane.setHgrow(timeBox,       Priority.ALWAYS);
        GridPane.setHgrow(scheduleCombo, Priority.ALWAYS);
        GridPane.setHgrow(endDatePicker, Priority.ALWAYS);
        GridPane.setHgrow(daysBox,       Priority.ALWAYS);
        GridPane.setHgrow(notesArea,     Priority.ALWAYS);

        formModeLabel = new Label("Nova tarefa");
        formModeLabel.getStyleClass().add("section-title");

        submitBtn = new Button("+ Adicionar tarefa");
        submitBtn.getStyleClass().add("primary-button");
        submitBtn.setMaxWidth(Double.MAX_VALUE);
        submitBtn.setOnAction(e -> submitForm());

        cancelEditBtn = new Button("Cancelar edição");
        cancelEditBtn.getStyleClass().add("secondary-button");
        cancelEditBtn.setMaxWidth(Double.MAX_VALUE);
        cancelEditBtn.setOnAction(e -> resetForm());
        UIHelper.setConditionalVisible(cancelEditBtn, false);

        VBox formSection = new VBox(8, formModeLabel, form, submitBtn, cancelEditBtn);
        formSection.getStyleClass().add("section-card");
        formSection.setPadding(new Insets(12));

        // ── botões de ação sobre a tarefa selecionada ─────────────────────
        Button editBtn = new Button("✎  Editar selecionada");
        editBtn.getStyleClass().add("secondary-button"); editBtn.setMaxWidth(Double.MAX_VALUE);
        editBtn.setOnAction(e -> {
            DatabaseService.RowItem sel = currentMainListView != null
                    ? currentMainListView.getSelectionModel().getSelectedItem() : null;
            if (sel == null) { ctx.setStatus("Selecione uma tarefa para editar."); return; }
            AppContextHolder.get().taskService().findById(sel.id()).ifPresentOrElse(
                    this::loadTaskIntoForm, () -> ctx.setStatus("Tarefa não encontrada."));
        });

        Button doneBtn = new Button("✓  Concluir selecionada");
        doneBtn.getStyleClass().add("secondary-button"); doneBtn.setMaxWidth(Double.MAX_VALUE);
        doneBtn.setOnAction(e -> {
            DatabaseService.RowItem sel = currentMainListView != null
                    ? currentMainListView.getSelectionModel().getSelectedItem() : null;
            if (sel == null) { ctx.setStatus("Selecione uma tarefa."); return; }
            AppContextHolder.get().taskService().markDone(sel.id());
            refresh(); ctx.triggerDashboardRefresh();
            ctx.setStatus("Tarefa concluída.");
        });

        Button deleteBtn = new Button("✕  Remover selecionada");
        deleteBtn.getStyleClass().add("danger-button"); deleteBtn.setMaxWidth(Double.MAX_VALUE);
        deleteBtn.setOnAction(e -> {
            DatabaseService.RowItem sel = currentMainListView != null
                    ? currentMainListView.getSelectionModel().getSelectedItem() : null;
            if (sel == null) { ctx.setStatus("Selecione uma tarefa para remover."); return; }
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Confirmar remoção");
            confirm.setHeaderText("Remover tarefa selecionada?");
            confirm.setContentText("Esta ação é permanente e não pode ser desfeita.");
            confirm.showAndWait().ifPresent(btn -> {
                if (btn == ButtonType.OK) {
                    AppContextHolder.get().taskService().deleteTask(sel.id());
                    if (editingId != null && editingId == sel.id()) resetForm();
                    refresh(); ctx.triggerDashboardRefresh();
                    ctx.setStatus("Tarefa removida.");
                }
            });
        });

        VBox actionsSection = new VBox(6, editBtn, doneBtn, deleteBtn);
        actionsSection.getStyleClass().add("section-card"); actionsSection.setPadding(new Insets(10));

        // history button: shows sessions for selected task or for current period
        Button historyBtn = new Button("Histórico de sessões");
        historyBtn.getStyleClass().add("secondary-button"); historyBtn.setMaxWidth(Double.MAX_VALUE);
        historyBtn.setOnAction(e -> {
            // if there's a selected task in the current main list, show sessions for that task
            DatabaseService.RowItem sel = currentMainListView != null
                    ? currentMainListView.getSelectionModel().getSelectedItem() : null;
                if (sel != null) {
                new com.pessoal.agenda.ui.view.SessionHistoryWindow(
                        AppContextHolder.get().taskSessionRepository(), sel.id()).show();
                return;
            }

            // otherwise open sessions for the current period according to currentView
            java.time.LocalDate from, to;
            switch (currentView) {
                case DIA -> { from = currentDate; to = currentDate; }
                case SEMANA -> { from = currentDate.with(java.time.DayOfWeek.MONDAY); to = from.plusDays(6); }
                case MES -> { java.time.YearMonth ym = java.time.YearMonth.from(currentDate); from = ym.atDay(1); to = ym.atEndOfMonth(); }
                default -> { from = java.time.LocalDate.of(currentDate.getYear(), 1, 1); to = java.time.LocalDate.of(currentDate.getYear(), 12, 31); }
            }
            new com.pessoal.agenda.ui.view.SessionHistoryWindow(AppContextHolder.get().taskSessionRepository(), null).show();
        });

        // append history button to actions
        actionsSection.getChildren().add(historyBtn);

        // ── Exportar para Google Calendar ─────────────────────────────────
        Button exportIcsBtn = new Button("  Exportar para Google Calendar");
        exportIcsBtn.getStyleClass().add("secondary-button"); exportIcsBtn.setMaxWidth(Double.MAX_VALUE);
        exportIcsBtn.setOnAction(e -> exportToICalendar());
        actionsSection.getChildren().add(exportIcsBtn);

        // ── Imprimir relatório de tarefas ──────────────────────────────────
        Button printBtn = new Button("  Imprimir Relatório");
        printBtn.getStyleClass().add("secondary-button"); printBtn.setMaxWidth(Double.MAX_VALUE);
        printBtn.setOnAction(e -> printCurrentView());
        actionsSection.getChildren().add(printBtn);

        // ── Google Tasks ───────────────────────────────────────────────────
        Button googleTasksBtn = new Button("☁  Google Tasks");
        googleTasksBtn.getStyleClass().add("secondary-button");
        googleTasksBtn.setMaxWidth(Double.MAX_VALUE);
        googleTasksBtn.setOnAction(e ->
            new com.pessoal.agenda.ui.view.GoogleTasksSyncWindow(() -> {
                refresh(); ctx.triggerDashboardRefresh();
            }).show());
        actionsSection.getChildren().addAll(new Separator(), googleTasksBtn);

        ListView<String> alertsList = new ListView<>(ctx.alertItems);
        alertsList.getStyleClass().add("clean-list");
        VBox.setVgrow(alertsList, Priority.ALWAYS);
        VBox alertsSection = UIHelper.createCardSection("Alertas e riscos", alertsList);
        VBox.setVgrow(alertsSection, Priority.ALWAYS);

        VBox side = new VBox(10, formSection, actionsSection, alertsSection);
        side.setPadding(new Insets(14, 0, 14, 0));
        return side;
    }

    // ── Formulário: submissão / carga / reset ──────────────────────────────

    private void submitForm() {
        if (titleField.getText().isBlank() || startPicker.getValue() == null) {
            ctx.setStatus("Informe título e data de início."); return;
        }
        String sv = scheduleCombo.getValue();
        ScheduleType st = switch (sv) {
            case "Intervalo de datas" -> ScheduleType.RANGE;
            case "Dias da semana"     -> ScheduleType.WEEKLY;
            default                   -> ScheduleType.SINGLE;
        };
        LocalDate endDate = (st == ScheduleType.SINGLE) ? null : endDatePicker.getValue();
        String recDays = null;
        if (st == ScheduleType.WEEKLY) {
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < 7; i++) {
                if (dayChecks[i].isSelected()) { if (!sb.isEmpty()) sb.append(","); sb.append(i); }
            }
            recDays = sb.toString();
        }
        TaskPriority priority = resolvePriority(priorityCombo.getValue());
        TaskStatus   status   = resolveStatus(statusCombo.getValue());
        try {
            var svc = AppContextHolder.get().taskService();
            if (editingId == null) {
                svc.createTask(titleField.getText().trim(), notesArea.getText().trim(),
                        startPicker.getValue(), catCombo.getValue(),
                        st, endDate, recDays,
                        startTimeField.getText(), endTimeField.getText(), priority, status);
                ctx.setStatus("Tarefa registrada com sucesso.");
            } else {
                svc.updateTask(editingId,
                        titleField.getText().trim(), notesArea.getText().trim(),
                        startPicker.getValue(), catCombo.getValue(),
                        st, endDate, recDays,
                        startTimeField.getText(), endTimeField.getText(), priority, status);
                ctx.setStatus("Tarefa atualizada: " + titleField.getText().trim());
            }
            resetForm();
            refresh(); ctx.triggerDashboardRefresh();
        } catch (IllegalArgumentException ex) {
            ctx.setStatus("Erro: " + ex.getMessage());
        }
    }

    private void loadTaskIntoForm(Task t) {
        editingId = t.id();
        titleField.setText(t.title());
        notesArea.setText(t.notes() != null ? t.notes() : "");
        startPicker.setValue(t.dueDate());
        startTimeField.setText(t.startTime() != null ? t.startTime() : "");
        endTimeField.setText(t.endTime()   != null ? t.endTime()   : "");
        if (t.category() != null && ctx.taskCatNames.contains(t.category()))
            catCombo.setValue(t.category());
        priorityCombo.setValue(t.priority() != null ? t.priority().label() : TaskPriority.NORMAL.label());
        statusCombo.setValue(t.status() != null ? t.status().label() : TaskStatus.PENDENTE.label());
        ScheduleType sched = t.scheduleType() != null ? t.scheduleType() : ScheduleType.SINGLE;
        scheduleCombo.setValue(switch (sched) {
            case RANGE  -> "Intervalo de datas";
            case WEEKLY -> "Dias da semana";
            default     -> "Dia único";
        });
        if (t.endDate() != null) endDatePicker.setValue(t.endDate());
        if (t.recurrenceDays() != null && !t.recurrenceDays().isBlank()) {
            String[] active = t.recurrenceDays().split(",");
            for (int i = 0; i < 7; i++) {
                final String di = String.valueOf(i);
                dayChecks[i].setSelected(java.util.Arrays.stream(active).anyMatch(di::equals));
            }
        }
        boolean hasEnd = sched == ScheduleType.RANGE || sched == ScheduleType.WEEKLY;
        UIHelper.setConditionalVisible(endDateLabel,  hasEnd);
        UIHelper.setConditionalVisible(endDatePicker, hasEnd);
        UIHelper.setConditionalVisible(daysLabel,     sched == ScheduleType.WEEKLY);
        UIHelper.setConditionalVisible(daysBox,       sched == ScheduleType.WEEKLY);
        formModeLabel.setText("Editando: \"" + t.title() + "\"");
        submitBtn.setText("Salvar alterações");
        UIHelper.setConditionalVisible(cancelEditBtn, true);
        ctx.setStatus("Formulário preenchido — edite os campos e salve.");
    }

    private void resetForm() {
        editingId = null;
        titleField.clear(); notesArea.clear();
        startPicker.setValue(LocalDate.now());
        startTimeField.clear(); endTimeField.clear();
        catCombo.setValue(ctx.taskCatNames.isEmpty() ? "Geral" : ctx.taskCatNames.get(0));
        priorityCombo.setValue(TaskPriority.NORMAL.label());
        statusCombo.setValue(TaskStatus.PENDENTE.label());
        scheduleCombo.setValue("Dia único");
        UIHelper.setConditionalVisible(endDateLabel,  false);
        UIHelper.setConditionalVisible(endDatePicker, false);
        UIHelper.setConditionalVisible(daysLabel,     false);
        UIHelper.setConditionalVisible(daysBox,       false);
        for (int i = 0; i < 7; i++) dayChecks[i].setSelected(i >= 1 && i <= 5);
        formModeLabel.setText("Nova tarefa");
        submitBtn.setText("+ Adicionar tarefa");
        UIHelper.setConditionalVisible(cancelEditBtn, false);
    }

    // ── Construtores de view ───────────────────────────────────────────────

    private Node buildDayContent() {
        dayTaskItems.setAll(db.listTasksByDay(currentDate, categoryFilter));
        if (dayTaskItems.isEmpty()) {
            Label empty = new Label("Nenhuma tarefa para este dia.");
            empty.getStyleClass().add("empty-state-label");
            VBox box = new VBox(empty); box.setAlignment(Pos.CENTER); box.setPrefHeight(220);
            return box;
        }
        ListView<DatabaseService.RowItem> list = new ListView<>(dayTaskItems);
        list.getStyleClass().add("clean-list");
        list.getSelectionModel().setSelectionMode(SelectionMode.SINGLE);
        currentMainListView = list;
        list.setOnMouseClicked(e -> {
            if (e.getButton() == javafx.scene.input.MouseButton.SECONDARY) {
                DatabaseService.RowItem sel = list.getSelectionModel().getSelectedItem();
                if (sel != null) showTaskContextMenu(sel, list, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getClickCount() == 2 && e.getButton() == javafx.scene.input.MouseButton.PRIMARY) {
                DatabaseService.RowItem sel = list.getSelectionModel().getSelectedItem();
                if (sel != null) {
                    AppContextHolder.get().taskService().findById(sel.id()).ifPresent(t ->
                        new com.pessoal.agenda.ui.view.TaskTimerWindow(t, AppContextHolder.get().taskSessionRepository()).show());
                }
            }
        });
        VBox.setVgrow(list, Priority.ALWAYS);
        VBox box = new VBox(list); VBox.setVgrow(box, Priority.ALWAYS);
        return box;
    }

    private Node buildWeekContent() {
        LocalDate weekStart = currentDate.with(DayOfWeek.MONDAY);
        LocalDate today     = LocalDate.now();
        String[] dayNames   = {"Seg","Ter","Qua","Qui","Sex","Sáb","Dom"};
        HBox weekBox = new HBox(6); weekBox.setFillHeight(true);
        for (int i = 0; i < 7; i++) {
            LocalDate day     = weekStart.plusDays(i);
            boolean   isToday = day.equals(today);
            weekDayItems.get(i).setAll(db.listTasksByDay(day, categoryFilter));
            Label header = new Label(dayNames[i] + "\n" + day.getDayOfMonth() + "/" + day.getMonthValue());
            header.getStyleClass().add(isToday ? "day-column-header-today" : "day-column-header");
            header.setMaxWidth(Double.MAX_VALUE); header.setAlignment(Pos.CENTER);
            ListView<DatabaseService.RowItem> dayList = new ListView<>(weekDayItems.get(i));
            dayList.getStyleClass().add("clean-list"); VBox.setVgrow(dayList, Priority.ALWAYS);
            dayList.setOnMouseClicked(ev -> {
                if (ev.getButton() == javafx.scene.input.MouseButton.SECONDARY) {
                    DatabaseService.RowItem sel = dayList.getSelectionModel().getSelectedItem();
                    if (sel != null) showTaskContextMenu(sel, dayList, ev.getScreenX(), ev.getScreenY());
                    ev.consume();
                } else if (ev.getClickCount() == 2 && ev.getButton() == javafx.scene.input.MouseButton.PRIMARY) {
                    DatabaseService.RowItem sel = dayList.getSelectionModel().getSelectedItem();
                    if (sel != null) {
                        AppContextHolder.get().taskService().findById(sel.id()).ifPresent(t ->
                            new com.pessoal.agenda.ui.view.TaskTimerWindow(t, AppContextHolder.get().taskSessionRepository()).show());
                    }
                }
            });
            dayList.getSelectionModel().selectedItemProperty().addListener(
                    (obs, o, n) -> { if (n != null) currentMainListView = dayList; });
            VBox col = new VBox(6, header, dayList);
            col.getStyleClass().add("day-column");
            if (isToday) col.getStyleClass().add("day-column-today");
            col.setPadding(new Insets(8)); col.setPrefWidth(160);
            HBox.setHgrow(col, Priority.ALWAYS);
            weekBox.getChildren().add(col);
        }
        ScrollPane scroll = new ScrollPane(weekBox);
        scroll.setFitToHeight(true); scroll.setFitToWidth(true);
        scroll.getStyleClass().add("edge-to-edge"); VBox.setVgrow(scroll, Priority.ALWAYS);
        return scroll;
    }

    private Node buildMonthContent() {
        taskItems.setAll(db.listTasksByMonthFiltered(YearMonth.from(currentDate), categoryFilter));
        ListView<DatabaseService.RowItem> list = new ListView<>(taskItems);
        list.getStyleClass().add("clean-list");
        list.getSelectionModel().setSelectionMode(SelectionMode.SINGLE);
        currentMainListView = list; VBox.setVgrow(list, Priority.ALWAYS);
        // Custom cell: mostra controles do timer se for a tarefa ativa
        list.setCellFactory(lv -> new ListCell<>() {
            private final HBox cellBox = new HBox(8);
            private final Label textLabel = new Label();
            private final Label timerLabel = new Label();
            private final Button playPauseBtn = new Button();
            private final Button stopBtn = new Button();
            private final Button resetBtn = new Button();
            private Long cellTaskId = null;
            private Runnable tickUnsubscriber = null;
            {
                playPauseBtn.setPrefWidth(32); playPauseBtn.setFocusTraversable(false);
                stopBtn.setPrefWidth(32); stopBtn.setFocusTraversable(false);
                resetBtn.setPrefWidth(32); resetBtn.setFocusTraversable(false);
                playPauseBtn.setText("▶");
                stopBtn.setText("■");
                resetBtn.setText("⟲");
                timerLabel.getStyleClass().add("timer-label-inline");
                cellBox.setAlignment(Pos.CENTER_LEFT);
            }
            @Override
            protected void updateItem(DatabaseService.RowItem item, boolean empty) {
                super.updateItem(item, empty);
                if (empty || item == null) {
                    setGraphic(null); setText(null); cellTaskId = null;
                    if (tickUnsubscriber != null) { tickUnsubscriber.run(); tickUnsubscriber = null; }
                    return;
                }
                cellTaskId = item.id();
                var timerService = com.pessoal.agenda.service.TaskTimerService.get();
                if (timerService.getActiveTaskId() != null && timerService.getActiveTaskId().equals(item.id())) {
                    // Timer ativo para esta tarefa: mostra controles
                    textLabel.setText(item.text());
                    // Atualiza label do timer
                    long s = timerService.getElapsedSeconds();
                    timerLabel.setText(formatTimer(s));
                    // Atualização em tempo real (múltiplos listeners)
                    if (tickUnsubscriber != null) { tickUnsubscriber.run(); tickUnsubscriber = null; }
                    java.util.function.Consumer<Long> tickListener = sec -> {
                        if (cellTaskId != null && timerService.getActiveTaskId() != null && timerService.getActiveTaskId().equals(cellTaskId)) {
                            javafx.application.Platform.runLater(() -> timerLabel.setText(formatTimer(sec)));
                        }
                    };
                    timerService.addTickListener(tickListener);
                    tickUnsubscriber = () -> timerService.removeTickListener(tickListener);
                    // Botões
                    playPauseBtn.setText(timerService.isRunning() ? "⏸" : "▶");
                    playPauseBtn.setOnAction(e -> {
                        if (timerService.isRunning()) timerService.pause(); else timerService.resume();
                        playPauseBtn.setText(timerService.isRunning() ? "⏸" : "▶");
                    });
                    stopBtn.setOnAction(e -> {
                        // Ao parar, exibe o mesmo diálogo de salvar sessão do TaskTimerWindow
                        var task = db.findTaskById(cellTaskId);
                        if (task != null) {
                            com.pessoal.agenda.ui.view.TaskTimerWindow.showSaveSessionDialog(
                                task,
                                db.getTaskSessionRepository(),
                                null,
                                () -> { list.refresh(); }
                            );
                        } else {
                            timerService.stop();
                            list.refresh();
                        }
                    });
                    resetBtn.setOnAction(e -> { timerService.reset(); });
                    cellBox.getChildren().setAll(textLabel, timerLabel, playPauseBtn, stopBtn, resetBtn);
                    setGraphic(cellBox); setText(null);
                } else {
                    // Não é a tarefa ativa: mostra só o texto
                    setGraphic(null); setText(item.text());
                    if (tickUnsubscriber != null) { tickUnsubscriber.run(); tickUnsubscriber = null; }
                }
            }
            private String formatTimer(long s) {
                long hh = s / 3600, mm = (s % 3600) / 60, ss = s % 60;
                return String.format("%02d:%02d:%02d", hh, mm, ss);
            }
        });
        list.setOnMouseClicked(e -> {
            if (e.getButton() == javafx.scene.input.MouseButton.SECONDARY) {
                DatabaseService.RowItem sel = list.getSelectionModel().getSelectedItem();
                if (sel != null) showTaskContextMenu(sel, list, e.getScreenX(), e.getScreenY());
                e.consume();
            } else if (e.getClickCount() == 2 && e.getButton() == javafx.scene.input.MouseButton.PRIMARY) {
                DatabaseService.RowItem sel = list.getSelectionModel().getSelectedItem();
                if (sel != null) {
                    AppContextHolder.get().taskService().findById(sel.id()).ifPresent(task -> {
                        new com.pessoal.agenda.ui.view.TaskTimerWindow(
                            task,
                            AppContextHolder.get().taskSessionRepository(),
                            this::refreshMainListView // callback para refresh
                        ).show();
                    });
                }
            }
        });
        VBox box = new VBox(list); VBox.setVgrow(box, Priority.ALWAYS);
        return box;
    }

    private Node buildYearContent() {
        java.util.List<DatabaseService.MonthSummary> summaries =
                db.getYearOverview(currentDate.getYear(), categoryFilter);
        FlowPane grid = new FlowPane();
        grid.getStyleClass().add("year-grid"); grid.setHgap(10); grid.setVgap(10);
        for (DatabaseService.MonthSummary s : summaries) {
            Label nameLabel  = new Label(s.monthName()); nameLabel.getStyleClass().add("year-month-name");
            Label countLabel = new Label(String.valueOf(s.total())); countLabel.getStyleClass().add("year-month-count");
            Label openLabel  = new Label(s.open() == 0 ? "Sem pendências" : s.open() + " abertas");
            openLabel.getStyleClass().add("year-month-open");
            if (s.open() > 0) openLabel.setStyle("-fx-text-fill: #dc2626;");
            VBox card = new VBox(4, nameLabel, countLabel, openLabel);
            card.getStyleClass().add("year-month-card");
            int m = s.month();
            card.setOnMouseClicked(e -> {
                currentDate = LocalDate.of(currentDate.getYear(), m, 1);
                currentView = AgendaView.MES;
                refreshCurrentView();
            });
            grid.getChildren().add(card);
        }
        ScrollPane scroll = new ScrollPane(grid); scroll.setFitToWidth(true);
        scroll.getStyleClass().add("edge-to-edge"); VBox.setVgrow(scroll, Priority.ALWAYS);
        return scroll;
    }

    // ── Navegação e refresh ────────────────────────────────────────────────

    private ToggleButton buildViewToggle(String text, AgendaView view, ToggleGroup group) {
        ToggleButton btn = new ToggleButton(text);
        btn.setToggleGroup(group); btn.getStyleClass().add("view-toggle-btn");
        btn.setOnAction(e -> { currentView = view; refreshCurrentView(); });
        return btn;
    }

    private void navigateBack() {
        currentDate = switch (currentView) {
            case DIA    -> currentDate.minusDays(1);
            case SEMANA -> currentDate.minusWeeks(1);
            case MES    -> currentDate.minusMonths(1);
            case ANO    -> currentDate.minusYears(1);
        };
        refreshCurrentView();
    }

    private void navigateForward() {
        currentDate = switch (currentView) {
            case DIA    -> currentDate.plusDays(1);
            case SEMANA -> currentDate.plusWeeks(1);
            case MES    -> currentDate.plusMonths(1);
            case ANO    -> currentDate.plusYears(1);
        };
        refreshCurrentView();
    }

    private void refreshCurrentView() {
        if (contentArea == null || periodLabel == null) return;
        updatePeriodLabel();
        Node viewNode = switch (currentView) {
            case DIA    -> buildDayContent();
            case SEMANA -> buildWeekContent();
            case MES    -> buildMonthContent();
            case ANO    -> buildYearContent();
        };
        VBox.setVgrow(viewNode, Priority.ALWAYS);
        contentArea.getChildren().setAll(viewNode);
    }

    private void updatePeriodLabel() {
        Locale ptBR = Locale.forLanguageTag("pt-BR");
        DateTimeFormatter dayFmt  = DateTimeFormatter.ofPattern("EEEE, d 'de' MMMM 'de' yyyy", ptBR);
        DateTimeFormatter shortFmt= DateTimeFormatter.ofPattern("d MMM", ptBR);
        DateTimeFormatter monFmt  = DateTimeFormatter.ofPattern("MMMM 'de' yyyy", ptBR);
        String raw = switch (currentView) {
            case DIA    -> currentDate.format(dayFmt);
            case SEMANA -> {
                LocalDate start = currentDate.with(DayOfWeek.MONDAY);
                LocalDate end   = start.plusDays(6);
                yield "Semana de %s a %s de %d".formatted(
                        start.format(shortFmt), end.format(shortFmt), start.getYear());
            }
            case MES    -> YearMonth.from(currentDate).format(monFmt);
            case ANO    -> String.valueOf(currentDate.getYear());
        };
        periodLabel.setText(Character.toUpperCase(raw.charAt(0)) + raw.substring(1));
    }

    // ── Helpers ────────────────────────────────────────────────────────────

    private static TaskPriority resolvePriority(String label) {
        for (TaskPriority p : TaskPriority.values()) if (p.label().equals(label)) return p;
        return TaskPriority.NORMAL;
    }

    private static TaskStatus resolveStatus(String label) {
        for (TaskStatus s : TaskStatus.values()) if (s.label().equals(label)) return s;
        return TaskStatus.PENDENTE;
    }

    // Força refresh da lista principal (usado para atualizar células do timer)
    private void refreshMainListView() {
        if (currentMainListView != null) {
            javafx.application.Platform.runLater(() -> currentMainListView.refresh());
        }
    }

    // ── Menu popup de contexto para tarefas ──────────────────────────────────

    /** Menu popup (botão direito) para qualquer ListView de tarefas. */
    private ContextMenu taskContextMenu;

    private void showTaskContextMenu(DatabaseService.RowItem item,
                                     javafx.scene.control.ListView<?> owner,
                                     double screenX, double screenY) {
        if (taskContextMenu != null) taskContextMenu.hide();
        taskContextMenu = new ContextMenu();
        taskContextMenu.setAutoHide(true);

        MenuItem editItem = new MenuItem("✎  Editar tarefa");
        editItem.setOnAction(e -> AppContextHolder.get().taskService().findById(item.id())
                .ifPresentOrElse(this::loadTaskIntoForm, () -> ctx.setStatus("Tarefa não encontrada.")));

        MenuItem doneItem = new MenuItem("✔  Marcar como concluída");
        doneItem.setOnAction(e -> {
            AppContextHolder.get().taskService().markDone(item.id());
            refresh(); ctx.triggerDashboardRefresh();
            ctx.setStatus("Tarefa concluída.");
        });

        MenuItem timerItem = new MenuItem("▶  Abrir timer/sessão");
        timerItem.setOnAction(e -> AppContextHolder.get().taskService().findById(item.id()).ifPresent(
                t -> new com.pessoal.agenda.ui.view.TaskTimerWindow(
                        t, AppContextHolder.get().taskSessionRepository(), this::refreshMainListView).show()));

        MenuItem checklistItem = new MenuItem("☑  Abrir checklist");
        checklistItem.setOnAction(e -> AppContextHolder.get().taskService().findById(item.id()).ifPresent(
                t -> com.pessoal.agenda.ui.view.TaskChecklistWindow.open(t, this::refreshMainListView)));

        MenuItem historyItem = new MenuItem("  Histórico de sessões");
        historyItem.setOnAction(e -> new com.pessoal.agenda.ui.view.SessionHistoryWindow(
                AppContextHolder.get().taskSessionRepository(), item.id()).show());

        SeparatorMenuItem sep = new SeparatorMenuItem();

        MenuItem deleteItem = new MenuItem("✕  Remover tarefa");
        deleteItem.setStyle("-fx-text-fill: #c62828;");
        deleteItem.setOnAction(e -> {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Confirmar remoção");
            confirm.setHeaderText("Remover tarefa selecionada?");
            confirm.setContentText("Esta ação é permanente e não pode ser desfeita.");
            confirm.showAndWait().ifPresent(btn -> {
                if (btn == ButtonType.OK) {
                    AppContextHolder.get().taskService().deleteTask(item.id());
                    if (editingId != null && editingId == item.id()) resetForm();
                    refresh(); ctx.triggerDashboardRefresh();
                    ctx.setStatus("Tarefa removida.");
                }
            });
        });

        taskContextMenu.getItems().addAll(editItem, doneItem, timerItem, checklistItem, historyItem, sep, deleteItem);
        taskContextMenu.show(owner, screenX, screenY);
    }

    // ── Impressão de relatório de tarefas ─────────────────────────────────────

    private void printCurrentView() {
        Locale ptBR = Locale.forLanguageTag("pt-BR");

        // ── Passo 1: Descrição do período (sem chamadas ao BD) ────────────
        String periodDesc = switch (currentView) {
            case DIA    -> currentDate.format(DateTimeFormatter.ofPattern("dd/MM/yyyy", ptBR));
            case SEMANA -> {
                LocalDate ws = currentDate.with(DayOfWeek.MONDAY);
                yield "Semana " + ws.format(DateTimeFormatter.ofPattern("dd/MM", ptBR))
                    + " – " + ws.plusDays(6).format(DateTimeFormatter.ofPattern("dd/MM/yyyy", ptBR));
            }
            case ANO    -> "Ano " + currentDate.getYear();
            default     -> YearMonth.from(currentDate)
                               .format(DateTimeFormatter.ofPattern("MMMM 'de' yyyy", ptBR));
        };

        // ── Passo 2: Diálogo de filtros ───────────────────────────────────
        Label periodInfo = new Label(periodDesc);
        periodInfo.setStyle("-fx-font-weight: bold;");

        ComboBox<String> dlgCatCombo = new ComboBox<>();
        dlgCatCombo.getItems().add("Todas as categorias");
        dlgCatCombo.getItems().addAll(ctx.taskCatNames);
        dlgCatCombo.setValue(categoryFilter != null ? categoryFilter : "Todas as categorias");
        dlgCatCombo.getStyleClass().add("input-control");
        dlgCatCombo.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgStatusCombo = new ComboBox<>();
        dlgStatusCombo.getItems().addAll("Todos os status", "Pendente", "Em Andamento",
                "Concluída", "Bloqueada", "Cancelada", "Atrasada");
        dlgStatusCombo.setValue("Todos os status");
        dlgStatusCombo.getStyleClass().add("input-control");
        dlgStatusCombo.setMaxWidth(Double.MAX_VALUE);

        ComboBox<String> dlgPrioCombo = new ComboBox<>();
        dlgPrioCombo.getItems().addAll("Todas as prioridades", "Crítica", "Alta", "Normal", "Baixa");
        dlgPrioCombo.setValue("Todas as prioridades");
        dlgPrioCombo.getStyleClass().add("input-control");
        dlgPrioCombo.setMaxWidth(Double.MAX_VALUE);

        javafx.scene.layout.GridPane grid = new javafx.scene.layout.GridPane();
        grid.setHgap(10); grid.setVgap(8); grid.setPadding(new Insets(10, 0, 0, 0));
        grid.add(new Label("Período:"),    0, 0); grid.add(periodInfo,     1, 0);
        grid.add(new Label("Categoria:"),  0, 1); grid.add(dlgCatCombo,    1, 1);
        grid.add(new Label("Status:"),     0, 2); grid.add(dlgStatusCombo, 1, 2);
        grid.add(new Label("Prioridade:"), 0, 3); grid.add(dlgPrioCombo,   1, 3);
        javafx.scene.layout.GridPane.setHgrow(dlgCatCombo,    Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgStatusCombo, Priority.ALWAYS);
        javafx.scene.layout.GridPane.setHgrow(dlgPrioCombo,   Priority.ALWAYS);

        Dialog<ButtonType> printDlg = new Dialog<>();
        printDlg.setTitle("Opções de Impressão");
        printDlg.setHeaderText("Agenda e Prioridades — Filtros para impressão");
        printDlg.getDialogPane().setContent(grid);
        printDlg.getDialogPane().setMinWidth(420);
        printDlg.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.OK)).setText(" Gerar Relatório");
        ((Button) printDlg.getDialogPane().lookupButton(ButtonType.CANCEL)).setText("Cancelar");

        var dlgResult = printDlg.showAndWait();
        if (dlgResult.isEmpty() || dlgResult.get() != ButtonType.OK) return;

        // ── Passo 3: Ler valores do diálogo ───────────────────────────────
        String printCat  = "Todas as categorias".equals(dlgCatCombo.getValue()) ? null : dlgCatCombo.getValue();
        String statusSel = dlgStatusCombo.getValue();
        String prioSel   = dlgPrioCombo.getValue();

        // ── Passo 4: Buscar tarefas do período com filtro de categoria ────
        var repo = AppContextHolder.get().taskRepository();
        List<Task> tasks;
        switch (currentView) {
            case DIA -> {
                tasks = new java.util.ArrayList<>(repo.findByDay(currentDate, printCat));
            }
            case SEMANA -> {
                LocalDate weekStart = currentDate.with(DayOfWeek.MONDAY);
                java.util.LinkedHashMap<Long, Task> dedup = new java.util.LinkedHashMap<>();
                for (int i = 0; i < 7; i++) {
                    for (Task t : repo.findByDay(weekStart.plusDays(i), printCat)) dedup.putIfAbsent(t.id(), t);
                }
                tasks = new java.util.ArrayList<>(dedup.values());
            }
            case ANO -> {
                java.util.LinkedHashMap<Long, Task> dedup = new java.util.LinkedHashMap<>();
                for (int m = 1; m <= 12; m++) {
                    for (Task t : repo.findByMonth(YearMonth.of(currentDate.getYear(), m), printCat)) dedup.putIfAbsent(t.id(), t);
                }
                tasks = new java.util.ArrayList<>(dedup.values());
            }
            default -> {
                tasks = new java.util.ArrayList<>(repo.findByMonth(YearMonth.from(currentDate), printCat));
            }
        }

        // ── Passo 5: Aplicar filtro de status ─────────────────────────────
        if (!"Todos os status".equals(statusSel)) {
            tasks = tasks.stream().filter(t -> switch (statusSel) {
                case "Pendente"     -> !t.done() && t.status() == TaskStatus.PENDENTE && !t.isOverdue();
                case "Em Andamento" -> t.status() == TaskStatus.EM_ANDAMENTO;
                case "Concluída"    -> t.done() || t.status() == TaskStatus.CONCLUIDA;
                case "Bloqueada"    -> t.status() == TaskStatus.BLOQUEADA;
                case "Cancelada"    -> t.status() == TaskStatus.CANCELADA;
                case "Atrasada"     -> t.isOverdue() && !t.done();
                default             -> true;
            }).toList();
        }

        // ── Passo 6: Aplicar filtro de prioridade ─────────────────────────
        if (!"Todas as prioridades".equals(prioSel)) {
            tasks = tasks.stream().filter(t -> {
                String pn = t.priority() != null ? t.priority().name() : "NORMAL";
                return switch (prioSel) {
                    case "Crítica" -> "CRITICA".equals(pn);
                    case "Alta"    -> "ALTA".equals(pn);
                    case "Normal"  -> "NORMAL".equals(pn);
                    case "Baixa"   -> "BAIXA".equals(pn);
                    default        -> true;
                };
            }).toList();
        }

        String html = com.pessoal.agenda.ui.util.PrintReportService.generateAgendaReport(tasks, periodDesc);
        com.pessoal.agenda.ui.view.PrintPreviewWindow.open(html, "Agenda e Prioridades — " + periodDesc);
    }

    // ── Exportação para Google Calendar (iCalendar .ics) ──────────────────────

    private void exportToICalendar() {
        List<Task> tasks;
        String periodDesc;
        Locale ptBR = Locale.forLanguageTag("pt-BR");
        var repo = AppContextHolder.get().taskRepository();

        switch (currentView) {
            case DIA -> {
                tasks = repo.findByDay(currentDate, categoryFilter);
                periodDesc = currentDate.format(DateTimeFormatter.ofPattern("dd/MM/yyyy", ptBR));
            }
            case SEMANA -> {
                LocalDate weekStart = currentDate.with(DayOfWeek.MONDAY);
                java.util.LinkedHashMap<Long, Task> dedup = new java.util.LinkedHashMap<>();
                for (int i = 0; i < 7; i++) {
                    for (Task t : repo.findByDay(weekStart.plusDays(i), categoryFilter)) {
                        dedup.putIfAbsent(t.id(), t);
                    }
                }
                tasks = new java.util.ArrayList<>(dedup.values());
                LocalDate weekEnd = weekStart.plusDays(6);
                periodDesc = "semana de " + weekStart.format(DateTimeFormatter.ofPattern("dd/MM", ptBR))
                           + " a " + weekEnd.format(DateTimeFormatter.ofPattern("dd/MM/yyyy", ptBR));
            }
            case ANO -> {
                java.util.LinkedHashMap<Long, Task> dedup = new java.util.LinkedHashMap<>();
                for (int m = 1; m <= 12; m++) {
                    for (Task t : repo.findByMonth(YearMonth.of(currentDate.getYear(), m), categoryFilter)) {
                        dedup.putIfAbsent(t.id(), t);
                    }
                }
                tasks = new java.util.ArrayList<>(dedup.values());
                periodDesc = "ano " + currentDate.getYear();
            }
            default -> { // MES
                tasks = repo.findByMonth(YearMonth.from(currentDate), categoryFilter);
                periodDesc = YearMonth.from(currentDate)
                        .format(DateTimeFormatter.ofPattern("MMMM 'de' yyyy", ptBR));
            }
        }

        if (tasks.isEmpty()) {
            new Alert(Alert.AlertType.INFORMATION,
                    "Não há tarefas no período selecionado para exportar.",
                    ButtonType.OK).showAndWait();
            return;
        }

        // Diálogo de confirmação
        Dialog<ButtonType> optDialog = new Dialog<>();
        optDialog.setTitle("Exportar para Google Calendar");
        optDialog.setHeaderText("Exportar tarefas — " + periodDesc);
        optDialog.setContentText(
                "Serão exportadas " + tasks.size() + " tarefa(s) no formato iCalendar (.ics).\n\n"
                + "Após salvar o arquivo, importe-o no Google Calendar:\n"
                + "  1. Acesse calendar.google.com\n"
                + "  2. Configurações ⚙ → Importar e exportar → Importar\n"
                + "  3. Selecione o arquivo .ics gerado\n"
                + "  4. Escolha o calendário de destino e clique em Importar");
        optDialog.getDialogPane().getButtonTypes().addAll(ButtonType.OK, ButtonType.CANCEL);
        ((Button) optDialog.getDialogPane().lookupButton(ButtonType.OK)).setText("Salvar arquivo .ics");

        optDialog.showAndWait().ifPresent(btn -> {
            if (btn != ButtonType.OK) return;

            FileChooser fc = new FileChooser();
            fc.setTitle("Salvar arquivo iCalendar");
            fc.setInitialFileName("agenda-cientifica-" + currentDate.getYear() + ".ics");
            fc.getExtensionFilters().add(
                    new FileChooser.ExtensionFilter("Arquivos iCalendar (*.ics)", "*.ics"));

            Stage owner = (Stage) contentArea.getScene().getWindow();
            File dest = fc.showSaveDialog(owner);
            if (dest == null) return;

            try {
                ICalendarExporter.export(tasks, dest.toPath());
                ctx.setStatus("✅ Exportado: " + dest.getName() + " (" + tasks.size() + " tarefa(s))");

                Alert success = new Alert(Alert.AlertType.INFORMATION);
                success.setTitle("Exportação concluída");
                success.setHeaderText("Arquivo iCalendar gerado com sucesso!");
                success.setContentText(
                        "Arquivo salvo em:\n" + dest.getAbsolutePath() + "\n\n"
                        + "Para importar no Google Calendar:\n"
                        + "  1. Acesse calendar.google.com\n"
                        + "  2. Clique em Configurações ⚙ (canto superior direito)\n"
                        + "  3. Va em \"Importar e exportar\"\n"
                        + "  4. Clique em \"Importar\" e selecione o arquivo\n"
                        + "  5. Escolha o calendario de destino e confirme\n\n"
                        + "Compativel tambem com Outlook, Apple Calendar\n"
                        + "e qualquer app que suporte iCalendar (RFC 5545).");
                success.showAndWait();
            } catch (IOException ex) {
                ctx.setStatus("Erro ao exportar: " + ex.getMessage());
                new Alert(Alert.AlertType.ERROR,
                        "Erro ao gerar o arquivo:\n" + ex.getMessage(), ButtonType.OK).showAndWait();
            }
        });
    }
}

package com.pessoal.agenda.ui.view;

import com.pessoal.agenda.app.AppContextHolder;
import com.pessoal.agenda.service.GoogleAuthService;
import com.pessoal.agenda.service.GoogleTasksService;
import com.pessoal.agenda.service.GoogleTasksService.GTask;
import com.pessoal.agenda.service.GoogleTasksService.SyncResult;
import com.pessoal.agenda.service.GoogleTasksService.TaskList;
import javafx.application.Platform;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.concurrent.Task;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.*;
import javafx.stage.Modality;
import javafx.stage.Stage;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Janela de sincronização BIDIRECIONAL com o Google Tasks.
 *
 * Fluxo de sync:
 *  - Google task sem mapeamento → cria localmente
 *  - Local task sem mapeamento  → cria no Google
 *  - Concluída em qualquer lado → conclui nos dois
 *  - Texto local → atualiza no Google (local é fonte de verdade para texto)
 */
public class GoogleTasksSyncWindow {

    private static Stage openStage;

    private final GoogleAuthService  auth;
    private final GoogleTasksService gTasks;
    private final Runnable           onSyncCallback;

    private Stage  stage;
    private Label  statusLabel;
    private Label  connectionLabel;
    private Button connectBtn;
    private Button disconnectBtn;
    private Button syncBtn;

    // Google side
    private ComboBox<TaskList>    listCombo;
    private ObservableList<GTask> gTaskItems = FXCollections.observableArrayList();
    private ListView<GTask>       gTaskList;

    // Local side
    private ObservableList<com.pessoal.agenda.model.Task> localItems = FXCollections.observableArrayList();
    private ListView<com.pessoal.agenda.model.Task>       localList;

    // Log de sync
    private TextArea logArea;

    private static final DateTimeFormatter DATE_FMT = DateTimeFormatter.ofPattern("dd/MM/yyyy");

    public GoogleTasksSyncWindow(Runnable onSyncCallback) {
        this.auth          = GoogleAuthService.getInstance();
        this.gTasks        = new GoogleTasksService();
        this.onSyncCallback = onSyncCallback;
    }

    public void show() {
        if (openStage != null && openStage.isShowing()) {
            openStage.toFront(); openStage.requestFocus(); return;
        }

        stage = new Stage();
        stage.setTitle("☁  Google Tasks — Sincronização Bidirecional");
        stage.setMinWidth(920);
        stage.setMinHeight(560);
        stage.initModality(Modality.APPLICATION_MODAL);

        VBox root = new VBox(0);
        root.getStyleClass().add("app-root");
        root.getChildren().addAll(buildHeader(), buildSyncBar(), buildCenter(), buildBottom());

        Scene scene = new Scene(root, 1060, 660);
        ThemeManager.getInstance().applyTo(scene);
        stage.setScene(scene);
        stage.setOnHidden(e -> openStage = null);

        openStage = stage;
        loadLocalTasks();
        if (auth.isAuthorized()) loadGoogleTaskLists();
        stage.show();
    }

    // ── Header ───────────────────────────────────────────────────────────────

    private HBox buildHeader() {
        Label title = new Label("☁  Google Tasks — Sincronização Bidirecional");
        title.getStyleClass().add("page-title");

        connectionLabel = new Label();
        updateConnectionLabel();

        connectBtn = new Button("  Conectar conta Google");
        connectBtn.getStyleClass().add("primary-button");
        connectBtn.setOnAction(e -> doConnect());

        disconnectBtn = new Button("✕  Desconectar");
        disconnectBtn.getStyleClass().add("danger-button");
        disconnectBtn.setOnAction(e -> doDisconnect());

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox header = new HBox(12, title, spacer, connectionLabel, connectBtn, disconnectBtn);
        header.setAlignment(Pos.CENTER_LEFT);
        header.setPadding(new Insets(14, 18, 12, 18));
        header.getStyleClass().add("header-bar");

        refreshConnectButtons();
        return header;
    }

    // ── Barra de sincronização central ───────────────────────────────────────

    private HBox buildSyncBar() {
        Label listLabel = new Label("Lista Google:");
        listLabel.setStyle("-fx-font-weight: 600;");

        listCombo = new ComboBox<>();
        listCombo.setPrefWidth(220);
        listCombo.getStyleClass().add("input-control");
        listCombo.setPromptText("Selecione uma lista...");
        listCombo.setOnAction(e -> { if (listCombo.getValue() != null) loadGoogleTasks(); });

        Button refreshListsBtn = new Button("↻");
        refreshListsBtn.getStyleClass().add("secondary-button");
        refreshListsBtn.setTooltip(new Tooltip("Recarregar listas do Google"));
        refreshListsBtn.setOnAction(e -> loadGoogleTaskLists());

        syncBtn = new Button("  Sincronizar Agora");
        syncBtn.getStyleClass().add("primary-button");
        syncBtn.setStyle("-fx-font-size: 13px; -fx-font-weight: 700;");
        syncBtn.setOnAction(e -> doSync());

        // Botões de ação manual
        Button importSelBtn = new Button("⬇  Importar selecionada");
        importSelBtn.getStyleClass().add("secondary-button");
        importSelBtn.setOnAction(e -> importSelected());

        Button exportSelBtn = new Button("⬆  Exportar selecionada");
        exportSelBtn.getStyleClass().add("secondary-button");
        exportSelBtn.setOnAction(e -> exportSelected());

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox bar = new HBox(10, listLabel, listCombo, refreshListsBtn, spacer,
                importSelBtn, exportSelBtn, new Separator(javafx.geometry.Orientation.VERTICAL),
                syncBtn);
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPadding(new Insets(10, 16, 10, 16));
        bar.setStyle("-fx-background-color: -t-surface; -fx-border-color: -t-border; -fx-border-width: 0 0 1 0;");
        return bar;
    }

    // ── Center ──────────────────────────────────────────────────────────────

    private SplitPane buildCenter() {
        SplitPane sp = new SplitPane(buildGooglePanel(), buildLocalPanel(), buildLogPanel());
        sp.setDividerPositions(0.38, 0.76);
        VBox.setVgrow(sp, Priority.ALWAYS);
        return sp;
    }

    private VBox buildGooglePanel() {
        Label title = new Label("  Google Tasks");
        title.setStyle("-fx-font-weight: 700; -fx-font-size: 13px;");

        gTaskList = new ListView<>(gTaskItems);
        gTaskList.getStyleClass().add("clean-list");
        gTaskList.setCellFactory(lv -> new ListCell<>() {
            @Override protected void updateItem(GTask t, boolean empty) {
                super.updateItem(t, empty);
                if (empty || t == null) { setGraphic(null); setText(null); return; }
                Label icon = new Label(t.completed() ? "✓" : "○");
                icon.setStyle("-fx-font-size:14px; -fx-text-fill:"
                        + (t.completed() ? "#27ae60;" : "-t-text;"));
                Label titleLbl = new Label(t.title() != null ? t.title() : "(sem título)");
                titleLbl.getStyleClass().add("study-plan-detail");
                if (t.completed()) titleLbl.setStyle("-fx-opacity:0.5;-fx-strikethrough:true;");
                HBox.setHgrow(titleLbl, Priority.ALWAYS);

                Label dateLbl = new Label(t.dueDate() != null ? t.dueDate().format(DATE_FMT) : "");
                dateLbl.setStyle("-fx-font-size:10px;-fx-opacity:0.6;");

                // Indica se tem mapeamento local
                boolean mapped = AppContextHolder.get()
                        .googleTasksMappingRepository()
                        .findByGoogleId(listCombo.getValue() != null ? listCombo.getValue().id() : "", t.id())
                        .isPresent();
                Label syncIcon = new Label(mapped ? "" : "");
                syncIcon.setStyle("-fx-font-size:10px;");

                HBox row = new HBox(6, icon, titleLbl, dateLbl, syncIcon);
                row.setAlignment(Pos.CENTER_LEFT);
                setGraphic(row); setText(null);
            }
        });
        VBox.setVgrow(gTaskList, Priority.ALWAYS);

        VBox panel = new VBox(8, title, gTaskList);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(gTaskList, Priority.ALWAYS);
        return panel;
    }

    private VBox buildLocalPanel() {
        Label title = new Label("  Tarefas Locais");
        title.setStyle("-fx-font-weight: 700; -fx-font-size: 13px;");

        localList = new ListView<>(localItems);
        localList.getStyleClass().add("clean-list");
        localList.setCellFactory(lv -> new ListCell<>() {
            @Override protected void updateItem(com.pessoal.agenda.model.Task t, boolean empty) {
                super.updateItem(t, empty);
                if (empty || t == null) { setGraphic(null); setText(null); return; }
                Label icon = new Label(t.done() ? "✓" : "○");
                icon.setStyle("-fx-font-size:14px;-fx-text-fill:"
                        + (t.done() ? "#27ae60;" : "-t-text;"));
                Label titleLbl = new Label(t.title());
                titleLbl.getStyleClass().add("study-plan-detail");
                if (t.done()) titleLbl.setStyle("-fx-opacity:0.5;-fx-strikethrough:true;");
                HBox.setHgrow(titleLbl, Priority.ALWAYS);

                Label dateLbl = new Label(t.dueDate().format(DATE_FMT));
                dateLbl.setStyle("-fx-font-size:10px;-fx-opacity:0.6;");

                String prioIcon = switch (t.priority()) {
                    case CRITICA -> "";
                    case ALTA    -> "";
                    case NORMAL  -> "";
                    case BAIXA   -> "⚪";
                };

                // Indica se tem mapeamento Google
                boolean mapped = AppContextHolder.get()
                        .googleTasksMappingRepository()
                        .findByLocalId(t.id()).isPresent();
                Label syncIcon = new Label(mapped ? "" : "");
                syncIcon.setStyle("-fx-font-size:10px;");

                HBox row = new HBox(6, icon, new Label(prioIcon), titleLbl, dateLbl, syncIcon);
                row.setAlignment(Pos.CENTER_LEFT);
                setGraphic(row); setText(null);
            }
        });
        VBox.setVgrow(localList, Priority.ALWAYS);

        VBox panel = new VBox(8, title, localList);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(localList, Priority.ALWAYS);
        return panel;
    }

    private VBox buildLogPanel() {
        Label title = new Label("  Log de Sincronização");
        title.setStyle("-fx-font-weight: 700; -fx-font-size: 13px;");

        logArea = new TextArea();
        logArea.setEditable(false);
        logArea.setWrapText(true);
        logArea.getStyleClass().add("input-control");
        logArea.setStyle("-fx-font-family: 'JetBrains Mono','Consolas',monospace; -fx-font-size: 11px;");
        logArea.setPromptText("O log da sincronização aparecerá aqui...");
        VBox.setVgrow(logArea, Priority.ALWAYS);

        Button clearBtn = new Button("Limpar log");
        clearBtn.getStyleClass().add("secondary-button");
        clearBtn.setOnAction(e -> logArea.clear());

        VBox panel = new VBox(8, title, logArea, clearBtn);
        panel.setPadding(new Insets(12));
        panel.getStyleClass().add("section-card");
        VBox.setVgrow(logArea, Priority.ALWAYS);
        return panel;
    }

    // ── Bottom ───────────────────────────────────────────────────────────────

    private HBox buildBottom() {
        statusLabel = new Label("Pronto.");
        statusLabel.setStyle("-fx-font-size: 11px; -fx-opacity: 0.7;");

        Button refreshLocalBtn = new Button("↻  Atualizar");
        refreshLocalBtn.getStyleClass().add("secondary-button");
        refreshLocalBtn.setOnAction(e -> { loadLocalTasks(); if (auth.isAuthorized()) loadGoogleTasks(); });

        Button closeBtn = new Button("Fechar");
        closeBtn.getStyleClass().add("secondary-button");
        closeBtn.setOnAction(e -> stage.close());

        Region spacer = new Region(); HBox.setHgrow(spacer, Priority.ALWAYS);
        HBox bar = new HBox(10, statusLabel, spacer, refreshLocalBtn, closeBtn);
        bar.setAlignment(Pos.CENTER_LEFT);
        bar.setPadding(new Insets(10, 14, 10, 14));
        bar.setStyle("-fx-border-color: -t-border; -fx-border-width: 1 0 0 0;");
        return bar;
    }

    // ── Lógica de conexão ────────────────────────────────────────────────────

    private void doConnect() {
        if (!auth.hasValidCredentials()) {
            showError("Credenciais não encontradas",
                "Arquivo não encontrado: ~/.agenda/google-credentials.json");
            return;
        }
        setStatus("Iniciando autorização OAuth...");
        runBackground(
            () -> { auth.authorize(msg -> Platform.runLater(() -> setStatus(msg))); return null; },
            result -> {
                updateConnectionLabel();
                refreshConnectButtons();
                setStatus("✓ Conectado ao Google Tasks!");
                loadGoogleTaskLists();
            },
            err -> showError("Erro de autorização", err.getMessage())
        );
    }

    private void doDisconnect() {
        Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
        confirm.setTitle("Desconectar Google Tasks");
        confirm.setHeaderText("Deseja desconectar sua conta do Google?");
        confirm.setContentText("Os tokens de acesso e mapeamentos serão removidos localmente.");
        confirm.showAndWait().filter(b -> b == ButtonType.OK).ifPresent(b -> {
            try {
                auth.revoke();
                gTaskItems.clear();
                listCombo.getItems().clear();
                updateConnectionLabel();
                refreshConnectButtons();
                setStatus("Desconectado.");
            } catch (Exception e) {
                showError("Erro ao desconectar", e.getMessage());
            }
        });
    }

    private void updateConnectionLabel() {
        if (auth.isAuthorized()) {
            connectionLabel.setText("● Conectado");
            connectionLabel.setStyle("-fx-text-fill: #27ae60; -fx-font-weight: 700;");
        } else {
            connectionLabel.setText("● Desconectado");
            connectionLabel.setStyle("-fx-text-fill: #e74c3c; -fx-font-weight: 700;");
        }
    }

    private void refreshConnectButtons() {
        boolean connected = auth.isAuthorized();
        connectBtn.setVisible(!connected); connectBtn.setManaged(!connected);
        disconnectBtn.setVisible(connected); disconnectBtn.setManaged(connected);
        if (syncBtn != null) syncBtn.setDisable(!connected);
    }

    // ── Sync Bidirecional ────────────────────────────────────────────────────

    private void doSync() {
        TaskList selected = listCombo.getValue();
        if (selected == null) { setStatus("Selecione uma lista do Google Tasks primeiro."); return; }
        if (!auth.isAuthorized()) { setStatus("Conecte ao Google primeiro."); return; }

        syncBtn.setDisable(true);
        setStatus(" Sincronizando com '" + selected.title() + "'...");
        appendLog("─── Iniciando sync: " + selected.title() + " ───");

        runBackground(
            () -> gTasks.syncBidirectional(
                    selected.id(),
                    AppContextHolder.get().taskRepository(),
                    AppContextHolder.get().googleTasksMappingRepository()),
            result -> {
                // Atualiza a UI
                loadLocalTasks();
                loadGoogleTasks();
                if (onSyncCallback != null) onSyncCallback.run();
                syncBtn.setDisable(false);

                // Mostra resultado
                String summary = String.format(
                    "✓ Sync concluído — ⬇ %d criado(s) local / ⬆ %d criado(s) Google" +
                    " / ✓ %d concluído(s) local / ✓ %d concluído(s) Google%s",
                    result.createdLocal(), result.createdGoogle(),
                    result.completedLocal(), result.completedGoogle(),
                    result.errors() > 0 ? " / ✗ " + result.errors() + " erro(s)" : "");
                setStatus(summary);

                for (String line : result.log()) appendLog(line);
                appendLog("─── Fim do sync ───\n");

                if (!result.hasChanges() && result.errors() == 0) {
                    appendLog("(nenhuma alteração detectada)");
                }
            },
            err -> {
                syncBtn.setDisable(false);
                appendLog("✗ ERRO FATAL: " + err.getMessage());
                showError("Erro na sincronização", err.getMessage());
            }
        );
    }

    // ── Ações manuais ────────────────────────────────────────────────────────

    private void importSelected() {
        GTask selected = gTaskList.getSelectionModel().getSelectedItem();
        if (selected == null) { setStatus("Selecione uma tarefa do Google para importar."); return; }
        if (!auth.isAuthorized()) { setStatus("Conecte ao Google primeiro."); return; }

        LocalDate due = selected.dueDate() != null ? selected.dueDate() : LocalDate.now();
        String notes  = selected.notes() != null && !selected.notes().isBlank() ? selected.notes() : null;
        AppContextHolder.get().taskRepository().save(selected.title(), notes, due, "Google Tasks");
        setStatus("Importada: " + selected.title());
        appendLog("⬇ Importada manualmente: " + selected.title());
        loadLocalTasks();
        if (onSyncCallback != null) onSyncCallback.run();
    }

    private void exportSelected() {
        com.pessoal.agenda.model.Task selected = localList.getSelectionModel().getSelectedItem();
        if (selected == null) { setStatus("Selecione uma tarefa local para exportar."); return; }
        if (!auth.isAuthorized()) { setStatus("Conecte ao Google primeiro."); return; }
        TaskList targetList = listCombo.getValue();
        if (targetList == null) { setStatus("Selecione uma lista do Google Tasks primeiro."); return; }

        runBackground(
            () -> gTasks.createTask(targetList.id(), selected.title(), selected.notes(), selected.dueDate()),
            gId -> {
                if (gId != null) {
                    AppContextHolder.get().googleTasksMappingRepository()
                            .upsert(selected.id(), targetList.id(), gId);
                }
                setStatus("⬆ Exportada: " + selected.title());
                appendLog("⬆ Exportada manualmente: " + selected.title());
                loadGoogleTasks();
                loadLocalTasks();
            },
            err -> showError("Erro ao exportar", err.getMessage())
        );
    }

    // ── Carregar dados ───────────────────────────────────────────────────────

    private void loadGoogleTaskLists() {
        if (!auth.isAuthorized()) return;
        setStatus("Carregando listas...");
        runBackground(
            () -> gTasks.listTaskLists(),
            lists -> {
                listCombo.getItems().setAll(lists);
                if (!lists.isEmpty()) { listCombo.setValue(lists.get(0)); loadGoogleTasks(); }
                setStatus("Listas: " + lists.size());
            },
            err -> showError("Erro ao carregar listas", err.getMessage())
        );
    }

    private void loadGoogleTasks() {
        TaskList selected = listCombo.getValue();
        if (selected == null || !auth.isAuthorized()) return;
        runBackground(
            () -> gTasks.listTasks(selected.id(), true),
            tasks -> { gTaskItems.setAll(tasks); gTaskList.refresh(); },
            err -> showError("Erro ao carregar tarefas Google", err.getMessage())
        );
    }

    private void loadLocalTasks() {
        List<com.pessoal.agenda.model.Task> tasks =
                AppContextHolder.get().taskRepository().findOpenTasks();
        localItems.setAll(tasks);
        if (localList != null) localList.refresh();
    }

    // ── helpers ──────────────────────────────────────────────────────────────

    private void setStatus(String msg) {
        Platform.runLater(() -> statusLabel.setText(msg));
    }

    private void appendLog(String msg) {
        Platform.runLater(() -> {
            if (logArea != null) {
                logArea.appendText(msg + "\n");
            }
        });
    }

    private void showError(String title, String msg) {
        Platform.runLater(() -> {
            Alert alert = new Alert(Alert.AlertType.ERROR);
            alert.setTitle(title);
            alert.setHeaderText(title);
            alert.setContentText(msg != null ? msg : "Erro desconhecido.");
            alert.showAndWait();
            appendLog("✗ " + title + ": " + msg);
        });
    }

    private <T> void runBackground(
            java.util.concurrent.Callable<T> action,
            java.util.function.Consumer<T>    onSuccess,
            java.util.function.Consumer<Throwable> onError) {

        Task<T> task = new Task<>() {
            @Override protected T call() throws Exception { return action.call(); }
        };
        task.setOnSucceeded(e -> onSuccess.accept(task.getValue()));
        task.setOnFailed(e -> {
            Throwable ex = task.getException();
            System.err.println("[GoogleTasks] Erro: " + ex.getMessage());
            onError.accept(ex);
        });
        Thread t = new Thread(task);
        t.setDaemon(true);
        t.start();
    }
}

